/**
 * Holo Golf VR — Game Manager (Round 3 Overhaul)
 * Central state machine: TITLE → COURSE_SELECT → PLAYING → HOLE_COMPLETE → COURSE_COMPLETE
 * New: stroke limit per hole, skip-to-next-hole, course-specific theme colors.
 */
import { World, Vector3 } from "@iwsdk/core";
import { BallController } from "./ball";
import { PutterController } from "./putter";
import { CourseManager, HoleData } from "./course";
import { EffectsManager } from "./effects";
import { AudioManager } from "./audio";

export const MAX_STROKES_PER_HOLE = 10;

export enum GameState {
  LOADING = "loading",
  TITLE = "title",
  COURSE_SELECT = "course_select",
  PLAYING = "playing",
  AIMING = "aiming",
  BALL_MOVING = "ball_moving",
  HOLE_COMPLETE = "hole_complete",
  COURSE_COMPLETE = "course_complete",
  SETTINGS = "settings",
  PAUSED = "paused",
}

export interface HoleScore {
  holeIndex: number;
  par: number;
  strokes: number;
  holeInOne: boolean;
}

export interface CourseScore {
  courseName: string;
  holes: HoleScore[];
  totalStrokes: number;
  totalPar: number;
  completed: boolean;
}

export class GameManager {
  state: GameState = GameState.LOADING;
  currentCourseIndex = 0;
  currentHoleIndex = 0;
  currentStrokes = 0;
  courseScore: CourseScore;
  bestScores: Map<string, number> = new Map();
  practiceMode = false;

  private world: World;
  courseManager: CourseManager;
  private ball: BallController;
  private putter: PutterController;
  private effects: EffectsManager;
  audio: AudioManager;
  private holeTransitionTimer = 0;
  private stateListeners: ((state: GameState) => void)[] = [];
  private preRestoreState: GameState = GameState.AIMING;

  // Ball last-safe position for OOB/hazard resets
  private lastSafeBallPos = new Vector3();

  // Event callbacks for external notifications
  onWaterHazard: (() => void) | null = null;

  constructor(
    world: World,
    courseManager: CourseManager,
    ball: BallController,
    putter: PutterController,
    effects: EffectsManager,
    audio: AudioManager,
  ) {
    this.world = world;
    this.courseManager = courseManager;
    this.ball = ball;
    this.putter = putter;
    this.effects = effects;
    this.audio = audio;
    this.courseScore = this.createEmptyScore("Neon Circuit");

    // Load best scores from localStorage
    this.loadBestScores();
  }

  onStateChange(listener: (state: GameState) => void) {
    this.stateListeners.push(listener);
  }

  setState(state: GameState) {
    this.state = state;
    this.stateListeners.forEach((l) => l(state));
  }

  startCourse(courseIndex: number) {
    this.currentCourseIndex = courseIndex;
    this.currentHoleIndex = 0;
    this.currentStrokes = 0;
    this.practiceMode = false;
    const course = this.courseManager.getCourse(courseIndex);
    this.courseScore = this.createEmptyScore(course.name);

    // Switch ambient music based on course
    this.audio.switchCourseAmbient(courseIndex);

    this.loadHole(0);
    this.setState(GameState.PLAYING);
  }

  startPracticeHole(courseIndex: number, holeIndex: number) {
    this.currentCourseIndex = courseIndex;
    this.currentHoleIndex = holeIndex;
    this.currentStrokes = 0;
    this.practiceMode = true;
    const course = this.courseManager.getCourse(courseIndex);
    this.courseScore = this.createEmptyScore(course.name + " (Practice)");

    this.audio.switchCourseAmbient(courseIndex);
    this.loadHole(holeIndex);
    this.setState(GameState.PLAYING);
  }

  loadHole(holeIndex: number) {
    this.currentHoleIndex = holeIndex;
    this.currentStrokes = 0;
    const course = this.courseManager.getCourse(this.currentCourseIndex);
    const hole = course.holes[holeIndex];

    // Clear previous hole geometry
    this.courseManager.clearCurrentHole();

    // Build new hole
    this.courseManager.buildHole(hole);

    // Position ball at tee
    this.ball.reset(hole.teePosition.clone());
    this.lastSafeBallPos.copy(hole.teePosition);

    // Position putter near ball
    this.putter.setActive(true);

    // Camera
    this.effects.holeTransition();

    this.audio.playHoleStart();
    this.setState(GameState.AIMING);
  }

  onStroke() {
    this.currentStrokes++;
    // Save position before the stroke for OOB recovery
    this.lastSafeBallPos.copy(this.ball.position);
    this.audio.playPutt();
    this.setState(GameState.BALL_MOVING);
  }

  onBallStopped() {
    if (this.state !== GameState.BALL_MOVING) return;

    // Check if ball is in hole
    const course = this.courseManager.getCourse(this.currentCourseIndex);
    const hole = course.holes[this.currentHoleIndex];
    const dist = this.ball.position.distanceTo(hole.holePosition);

    if (dist < 0.15) {
      // Ball is in the hole!
      this.completeHole();
    } else if (this.currentStrokes >= MAX_STROKES_PER_HOLE) {
      // Stroke limit reached — auto-complete with max strokes
      this.completeHole();
    } else {
      // Ball stopped but not in hole
      this.setState(GameState.AIMING);
    }
  }

  private completeHole() {
    const course = this.courseManager.getCourse(this.currentCourseIndex);
    const hole = course.holes[this.currentHoleIndex];
    const holeInOne = this.currentStrokes === 1;

    // Check if actually in hole for effects
    const inHole = this.ball.position.distanceTo(hole.holePosition) < 0.15;

    this.courseScore.holes[this.currentHoleIndex] = {
      holeIndex: this.currentHoleIndex,
      par: hole.par,
      strokes: this.currentStrokes,
      holeInOne,
    };

    this.courseScore.totalStrokes = this.courseScore.holes
      .filter((h) => h.strokes > 0)
      .reduce((sum, h) => sum + h.strokes, 0);

    // Effects
    if (inHole) {
      if (holeInOne) {
        this.effects.holeInOneEffect(this.ball.position);
        this.audio.playHoleInOne();
      } else if (this.currentStrokes <= hole.par) {
        this.effects.underParEffect(this.ball.position);
        this.audio.playUnderPar();
      } else {
        this.effects.holeCompleteEffect(this.ball.position);
        this.audio.playHoleComplete();
      }
      this.ball.sinkIntoHole(hole.holePosition);
    } else {
      // Stroke limit reached, ball didn't make it
      this.effects.strokeLimitEffect(this.ball.position);
      this.audio.playStrokeLimit();
    }

    this.putter.setActive(false);
    this.setState(GameState.HOLE_COMPLETE);
    this.holeTransitionTimer = 3.0;
  }

  // Skip hole transition timer (XR controller A/trigger press)
  skipToNextHole() {
    if (this.state !== GameState.HOLE_COMPLETE) return;
    this.holeTransitionTimer = 0;
    this.nextHole();
  }

  nextHole() {
    if (this.practiceMode) {
      // In practice mode, replay the same hole or go to complete
      this.completeCourse();
      return;
    }
    const course = this.courseManager.getCourse(this.currentCourseIndex);
    if (this.currentHoleIndex < course.holes.length - 1) {
      this.loadHole(this.currentHoleIndex + 1);
    } else {
      this.completeCourse();
    }
  }

  private completeCourse() {
    this.courseScore.completed = true;
    const key = `course_${this.currentCourseIndex}`;
    const best = this.bestScores.get(key);
    if (!best || this.courseScore.totalStrokes < best) {
      this.bestScores.set(key, this.courseScore.totalStrokes);
      this.saveBestScores();
    }
    this.setState(GameState.COURSE_COMPLETE);
    this.audio.playCourseComplete();
  }

  resetBall() {
    if (this.state !== GameState.AIMING) return;
    const course = this.courseManager.getCourse(this.currentCourseIndex);
    const hole = course.holes[this.currentHoleIndex];
    this.ball.reset(hole.teePosition.clone());
    this.audio.playReset();
  }

  // === Pause / Resume ===

  pause() {
    if (
      this.state !== GameState.AIMING &&
      this.state !== GameState.BALL_MOVING &&
      this.state !== GameState.PLAYING
    ) return;
    this.preRestoreState = this.state;
    this.setState(GameState.PAUSED);
  }

  resume() {
    if (this.state !== GameState.PAUSED) return;
    this.setState(this.preRestoreState);
  }

  isPaused(): boolean {
    return this.state === GameState.PAUSED;
  }

  // === Out-of-bounds / Water hazard reset ===

  saveSafeBallPosition() {
    this.lastSafeBallPos.copy(this.ball.position);
  }

  handleBallOOB() {
    // Penalty stroke
    this.currentStrokes++;
    // Reset ball to last safe position or tee
    const course = this.courseManager.getCourse(this.currentCourseIndex);
    const hole = course.holes[this.currentHoleIndex];
    const resetPos = this.lastSafeBallPos.lengthSq() > 0
      ? this.lastSafeBallPos.clone()
      : hole.teePosition.clone();
    this.ball.reset(resetPos);
    this.audio.playOOB();
    this.effects.strokeLimitEffect(resetPos);

    // Check if penalty brings us to stroke limit
    if (this.currentStrokes >= MAX_STROKES_PER_HOLE) {
      this.completeHole();
    } else {
      this.setState(GameState.AIMING);
    }
  }

  handleWaterHazard() {
    // Penalty stroke
    this.currentStrokes++;
    const course = this.courseManager.getCourse(this.currentCourseIndex);
    const hole = course.holes[this.currentHoleIndex];
    const resetPos = this.lastSafeBallPos.lengthSq() > 0
      ? this.lastSafeBallPos.clone()
      : hole.teePosition.clone();
    this.ball.reset(resetPos);
    this.audio.playSplash();
    this.effects.strokeLimitEffect(resetPos);

    // Fire external callback
    if (this.onWaterHazard) this.onWaterHazard();

    if (this.currentStrokes >= MAX_STROKES_PER_HOLE) {
      this.completeHole();
    } else {
      this.setState(GameState.AIMING);
    }
  }

  getCurrentHole(): HoleData | null {
    try {
      const course = this.courseManager.getCourse(this.currentCourseIndex);
      return course.holes[this.currentHoleIndex] || null;
    } catch {
      return null;
    }
  }

  getScoreName(strokes: number, par: number): string {
    const diff = strokes - par;
    if (strokes === 1) return "HOLE IN ONE!";
    if (strokes >= MAX_STROKES_PER_HOLE) return "MAX STROKES";
    if (diff <= -3) return "Albatross";
    if (diff === -2) return "Eagle";
    if (diff === -1) return "Birdie";
    if (diff === 0) return "Par";
    if (diff === 1) return "Bogey";
    if (diff === 2) return "Double Bogey";
    if (diff === 3) return "Triple Bogey";
    return `+${diff}`;
  }

  update(dt: number) {
    if (this.state === GameState.PAUSED) return;

    if (this.state === GameState.HOLE_COMPLETE) {
      this.holeTransitionTimer -= dt;
      if (this.holeTransitionTimer <= 0) {
        this.nextHole();
      }
    }

    // Check if ball stopped
    if (this.state === GameState.BALL_MOVING && this.ball.isStopped()) {
      this.onBallStopped();
    }

    // Check special zones while ball is moving or aiming (wind/ice/water)
    if (
      (this.state === GameState.BALL_MOVING || this.state === GameState.AIMING) &&
      this.ball.isActive
    ) {
      // Save safe position periodically when ball is on solid ground
      if (this.state === GameState.BALL_MOVING && this.ball.position.y > -0.5) {
        this.lastSafeBallPos.copy(this.ball.position);
      }

      const result = this.courseManager.checkBallZones(
        this.ball.position,
        this.ball.velocity,
      );

      // Water hazard
      if (result.inWater) {
        this.effects.splashEffect(this.ball.position); // splash particles
        this.handleWaterHazard();
        return;
      }

      // Teleporter
      if (result.teleported && result.teleportTarget) {
        this.ball.reset(result.teleportTarget);
        this.ball.velocity.set(0, 0, 0);
        this.audio.playTeleport();
        this.effects.teleportEffect(this.ball.position);
      }

      // Wind force
      this.ball.setWindForce(result.windForce);

      // Ice friction
      this.ball.setFrictionOverride(result.frictionOverride);
    }
  }

  private createEmptyScore(courseName: string): CourseScore {
    return {
      courseName,
      holes: Array.from({ length: 9 }, (_, i) => ({
        holeIndex: i,
        par: 3,
        strokes: 0,
        holeInOne: false,
      })),
      totalStrokes: 0,
      totalPar: 0,
      completed: false,
    };
  }

  private loadBestScores() {
    try {
      const data = localStorage.getItem("holo-golf-best");
      if (data) {
        const parsed = JSON.parse(data);
        Object.entries(parsed).forEach(([k, v]) => this.bestScores.set(k, v as number));
      }
    } catch {}
  }

  private saveBestScores() {
    try {
      const obj: Record<string, number> = {};
      this.bestScores.forEach((v, k) => (obj[k] = v));
      localStorage.setItem("holo-golf-best", JSON.stringify(obj));
    } catch {}
  }
}

/**
 * Holo Golf VR — Environment Builder (Round 3 Overhaul)
 * Holodeck-style environment with course-specific theming.
 * Each course gets distinct grid color, fog, starfield, and ambient geometry.
 */
import {
  World,
  Group,
  Mesh,
  PlaneGeometry,
  MeshBasicMaterial,
  MeshStandardMaterial,
  Color,
  DoubleSide,
  AdditiveBlending,
  AmbientLight,
  DirectionalLight,
  PointLight,
  Fog,
  SphereGeometry,
  BoxGeometry,
  EdgesGeometry,
  LineSegments,
  LineBasicMaterial,
  BufferGeometry,
  Float32BufferAttribute,
  Points,
  PointsMaterial,
  ConeGeometry,
  TorusGeometry,
} from "@iwsdk/core";

interface CourseTheme {
  fogColor: number;
  gridColor: number;
  gridOpacity: number;
  starColors: number[][];
  ambientShapes: { pos: number[]; size: number; color: number; speed: number; geo: "box" | "sphere" | "torus" | "cone" }[];
  pointLights: { pos: number[]; color: number; intensity: number }[];
}

const COURSE_THEMES: CourseTheme[] = [
  // Neon Circuit — clean cyan/green
  {
    fogColor: 0x000811,
    gridColor: 0x003344,
    gridOpacity: 0.4,
    starColors: [[0, 0.8, 1], [0.5, 0.5, 1], [1, 1, 1], [1, 0.3, 0.6]],
    ambientShapes: [
      { pos: [-8, 5, -12], size: 0.8, color: 0x00ffff, speed: 0.3, geo: "box" },
      { pos: [10, 7, -15], size: 1.2, color: 0x44ff88, speed: 0.2, geo: "box" },
      { pos: [-12, 3, 8], size: 0.6, color: 0x0088ff, speed: 0.4, geo: "sphere" },
      { pos: [6, 8, 10], size: 1.0, color: 0x00ccff, speed: 0.25, geo: "box" },
      { pos: [-5, 6, -20], size: 1.5, color: 0x44ffaa, speed: 0.15, geo: "torus" },
    ],
    pointLights: [
      { pos: [-5, 4, -5], color: 0x00ffff, intensity: 0.4 },
      { pos: [5, 3, 5], color: 0x44ff88, intensity: 0.3 },
    ],
  },
  // Quantum Field — purple/pink
  {
    fogColor: 0x080011,
    gridColor: 0x330044,
    gridOpacity: 0.35,
    starColors: [[0.8, 0.2, 0.6], [0.5, 0.2, 1], [1, 0.5, 0.8], [0.3, 0.3, 1]],
    ambientShapes: [
      { pos: [-10, 5, -12], size: 0.9, color: 0xff44aa, speed: 0.2, geo: "sphere" },
      { pos: [8, 7, -18], size: 1.3, color: 0x8844ff, speed: 0.15, geo: "torus" },
      { pos: [-15, 4, 6], size: 0.7, color: 0xaa66ff, speed: 0.35, geo: "box" },
      { pos: [12, 6, 8], size: 1.1, color: 0xff88cc, speed: 0.25, geo: "cone" },
      { pos: [-3, 8, -22], size: 1.6, color: 0xcc44ff, speed: 0.1, geo: "sphere" },
    ],
    pointLights: [
      { pos: [-5, 4, -5], color: 0xff44aa, intensity: 0.4 },
      { pos: [5, 3, 5], color: 0x8844ff, intensity: 0.3 },
    ],
  },
  // Cosmic Abyss — orange/red, ominous
  {
    fogColor: 0x0a0400,
    gridColor: 0x331100,
    gridOpacity: 0.3,
    starColors: [[1, 0.4, 0], [1, 0.6, 0.2], [1, 0.2, 0], [1, 0.8, 0.4]],
    ambientShapes: [
      { pos: [-12, 6, -14], size: 1.0, color: 0xff6600, speed: 0.15, geo: "sphere" },
      { pos: [9, 5, -16], size: 0.8, color: 0xff4400, speed: 0.25, geo: "cone" },
      { pos: [-8, 4, 10], size: 1.4, color: 0xffaa00, speed: 0.1, geo: "torus" },
      { pos: [14, 8, 6], size: 0.6, color: 0xff8800, speed: 0.3, geo: "box" },
      { pos: [-6, 7, -25], size: 2.0, color: 0xff2200, speed: 0.08, geo: "sphere" },
    ],
    pointLights: [
      { pos: [-5, 4, -5], color: 0xff6600, intensity: 0.5 },
      { pos: [5, 3, 5], color: 0xff4400, intensity: 0.35 },
    ],
  },
];

export class EnvironmentBuilder {
  private world: World;
  private starfield: Points | null = null;
  private gridPulseTime = 0;
  private gridLines: LineSegments | null = null;
  private ambientOrbs: Mesh[] = [];
  private dynamicPointLights: PointLight[] = [];
  private currentThemeIndex = -1;

  // Keep references for theme switching
  private themeGroup: Group;
  private gridGroup: Group;
  private starfieldGroup: Group;

  constructor(world: World) {
    this.world = world;
    this.themeGroup = new Group();
    this.gridGroup = new Group();
    this.starfieldGroup = new Group();
    world.scene.add(this.themeGroup);
    world.scene.add(this.gridGroup);
    world.scene.add(this.starfieldGroup);
  }

  build() {
    const scene = this.world.scene;

    // Base lighting (constant across themes)
    const ambient = new AmbientLight(0x112233, 0.4);
    scene.add(ambient);

    const dirLight = new DirectionalLight(0x4488cc, 0.6);
    dirLight.position.set(5, 10, 5);
    scene.add(dirLight);

    // Build ground plane (constant)
    const gridSize = 40;
    const groundGeo = new PlaneGeometry(gridSize, gridSize);
    const groundMat = new MeshStandardMaterial({
      color: 0x000a11,
      roughness: 1,
      metalness: 0,
    });
    const ground = new Mesh(groundGeo, groundMat);
    ground.rotation.x = -Math.PI / 2;
    ground.position.y = -0.02;
    scene.add(ground);

    // Apply default theme
    this.applyTheme(0);
  }

  applyTheme(courseIndex: number) {
    if (courseIndex === this.currentThemeIndex) return;
    this.currentThemeIndex = courseIndex;
    const theme = COURSE_THEMES[courseIndex] || COURSE_THEMES[0];

    // Clear previous theme elements
    this.clearThemeElements();

    // Fog
    this.world.scene.fog = new Fog(theme.fogColor, 10, 80);

    // Grid
    this.buildGrid(theme);

    // Starfield
    this.buildStarfield(theme);

    // Ambient geometry
    this.buildAmbientGeometry(theme);

    // Point lights
    for (const lightDef of theme.pointLights) {
      const light = new PointLight(lightDef.color, lightDef.intensity, 20);
      light.position.set(lightDef.pos[0], lightDef.pos[1], lightDef.pos[2]);
      this.themeGroup.add(light);
      this.dynamicPointLights.push(light);
    }
  }

  private clearThemeElements() {
    // Clear grid
    while (this.gridGroup.children.length > 0) {
      const child = this.gridGroup.children[0];
      this.gridGroup.remove(child);
    }
    this.gridLines = null;

    // Clear starfield
    while (this.starfieldGroup.children.length > 0) {
      const child = this.starfieldGroup.children[0];
      this.starfieldGroup.remove(child);
    }
    this.starfield = null;

    // Clear theme decorations
    while (this.themeGroup.children.length > 0) {
      const child = this.themeGroup.children[0];
      this.themeGroup.remove(child);
    }
    this.ambientOrbs = [];
    this.dynamicPointLights = [];
  }

  private buildGrid(theme: CourseTheme) {
    const gridSize = 40;
    const divisions = 40;
    const step = gridSize / divisions;
    const halfSize = gridSize / 2;

    const vertices: number[] = [];
    for (let i = 0; i <= divisions; i++) {
      const pos = -halfSize + i * step;
      vertices.push(pos, -0.01, -halfSize, pos, -0.01, halfSize);
      vertices.push(-halfSize, -0.01, pos, halfSize, -0.01, pos);
    }

    const geo = new BufferGeometry();
    geo.setAttribute("position", new Float32BufferAttribute(vertices, 3));

    const mat = new LineBasicMaterial({
      color: theme.gridColor,
      transparent: true,
      opacity: theme.gridOpacity,
    });

    this.gridLines = new LineSegments(geo, mat);
    this.gridGroup.add(this.gridLines);
  }

  private buildStarfield(theme: CourseTheme) {
    const count = 2000;
    const positions = new Float32Array(count * 3);
    const colors = new Float32Array(count * 3);

    for (let i = 0; i < count; i++) {
      const i3 = i * 3;
      const r = 30 + Math.random() * 50;
      const theta = Math.random() * Math.PI * 2;
      const phi = Math.random() * Math.PI;

      positions[i3] = r * Math.sin(phi) * Math.cos(theta);
      positions[i3 + 1] = Math.abs(r * Math.cos(phi)) + 2;
      positions[i3 + 2] = r * Math.sin(phi) * Math.sin(theta);

      const colorSet = theme.starColors[Math.floor(Math.random() * theme.starColors.length)];
      colors[i3] = colorSet[0];
      colors[i3 + 1] = colorSet[1];
      colors[i3 + 2] = colorSet[2];
    }

    const geo = new BufferGeometry();
    geo.setAttribute("position", new Float32BufferAttribute(positions, 3));
    geo.setAttribute("color", new Float32BufferAttribute(colors, 3));

    const mat = new PointsMaterial({
      size: 0.15,
      vertexColors: true,
      transparent: true,
      opacity: 0.8,
      blending: AdditiveBlending,
      sizeAttenuation: true,
    });

    this.starfield = new Points(geo, mat);
    this.starfieldGroup.add(this.starfield);
  }

  private buildAmbientGeometry(theme: CourseTheme) {
    for (const s of theme.ambientShapes) {
      let geo: any;
      switch (s.geo) {
        case "sphere":
          geo = new SphereGeometry(s.size, 12, 12);
          break;
        case "cone":
          geo = new ConeGeometry(s.size * 0.6, s.size * 1.2, 6);
          break;
        case "torus":
          geo = new TorusGeometry(s.size, s.size * 0.2, 8, 16);
          break;
        default:
          geo = new BoxGeometry(s.size, s.size, s.size);
      }

      const mat = new MeshBasicMaterial({
        color: s.color,
        transparent: true,
        opacity: 0.08,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(geo, mat);
      mesh.position.set(s.pos[0], s.pos[1], s.pos[2]);

      const edges = new EdgesGeometry(geo);
      const edgeMat = new LineBasicMaterial({
        color: s.color,
        transparent: true,
        opacity: 0.3,
      });
      mesh.add(new LineSegments(edges, edgeMat));

      (mesh as any).__rotSpeed = s.speed;
      this.ambientOrbs.push(mesh);
      this.themeGroup.add(mesh);
    }
  }

  update(dt: number) {
    // Rotate ambient geometry
    for (const orb of this.ambientOrbs) {
      const speed = (orb as any).__rotSpeed || 0.2;
      orb.rotation.x += speed * dt * 0.5;
      orb.rotation.y += speed * dt;
    }

    // Grid pulse
    if (this.gridLines) {
      this.gridPulseTime += dt;
      const pulse = 0.3 + Math.sin(this.gridPulseTime * 0.5) * 0.1;
      (this.gridLines.material as LineBasicMaterial).opacity = pulse;
    }

    // Slow starfield rotation
    if (this.starfield) {
      this.starfield.rotation.y += dt * 0.005;
    }
  }
}

/**
 * Holo Golf VR — Effects Manager (Round 3 Overhaul)
 * Visual effects: hole-in-one celebration, under-par sparkle, transitions,
 * stroke limit, course-specific particle palettes.
 */
import {
  World,
  Vector3,
  Group,
  Mesh,
  SphereGeometry,
  MeshBasicMaterial,
  Color,
  AdditiveBlending,
  RingGeometry,
  DoubleSide,
  CylinderGeometry,
  PointLight,
  BufferGeometry,
  Float32BufferAttribute,
  Points,
  PointsMaterial,
  TorusGeometry,
} from "@iwsdk/core";

interface Particle {
  mesh: Mesh;
  velocity: Vector3;
  life: number;
  maxLife: number;
}

interface ExpandingRing {
  mesh: Mesh;
  life: number;
  speed: number;
}

interface PulsingOrb {
  mesh: Mesh;
  life: number;
  maxLife: number;
  baseScale: number;
  pulseRate: number;
}

// Course-specific particle palettes
const COURSE_PALETTES = [
  [0x00ffff, 0x44ff88, 0x0088ff, 0x88aaff], // Neon Circuit
  [0xff44aa, 0x8844ff, 0xaa66ff, 0xff88cc], // Quantum Field
  [0xff6600, 0xffaa00, 0xff4400, 0xffcc44], // Cosmic Abyss
];

export class EffectsManager {
  private world: World;
  private particles: Particle[] = [];
  private rings: ExpandingRing[] = [];
  private orbs: PulsingOrb[] = [];
  private effectsGroup: Group;
  private transitionTimer = 0;
  private currentCourseIndex = 0;

  constructor(world: World) {
    this.world = world;
    this.effectsGroup = new Group();
    world.scene.add(this.effectsGroup);
  }

  setCourseIndex(index: number) {
    this.currentCourseIndex = index;
  }

  private getPalette(): number[] {
    return COURSE_PALETTES[this.currentCourseIndex] || COURSE_PALETTES[0];
  }

  holeInOneEffect(pos: Vector3) {
    // Massive particle burst + expanding rings + column of light + orbiting torus
    this.spawnParticleBurst(pos, 100, [0xffff00, 0xff8800, 0x00ffff, 0xff44aa, 0xffffff], 4.0);

    // Multiple expanding rings
    for (let i = 0; i < 6; i++) {
      this.spawnExpandingRing(
        pos.clone().add(new Vector3(0, 0.1 + i * 0.12, 0)),
        [0xffff00, 0xff8800, 0x00ffff, 0xffffff][i % 4],
        2.0 + i * 0.2,
      );
    }

    // Light column
    this.spawnLightColumn(pos, 0xffff00, 3.5);
    this.spawnLightColumn(pos.clone().add(new Vector3(0, 0, 0)), 0xffffff, 2.5);

    // Pulsing celebration orb
    this.spawnPulsingOrb(pos.clone().add(new Vector3(0, 0.5, 0)), 0xffff00, 3.0, 0.2);
  }

  underParEffect(pos: Vector3) {
    const palette = this.getPalette();
    this.spawnParticleBurst(pos, 50, [...palette, 0xffffff], 2.5);
    this.spawnExpandingRing(pos.clone().add(new Vector3(0, 0.1, 0)), palette[0], 1.5);
    this.spawnExpandingRing(pos.clone().add(new Vector3(0, 0.2, 0)), palette[1], 1.0);
    this.spawnPulsingOrb(pos.clone().add(new Vector3(0, 0.3, 0)), palette[0], 2.0, 0.15);
  }

  holeCompleteEffect(pos: Vector3) {
    const palette = this.getPalette();
    this.spawnParticleBurst(pos, 25, palette, 1.5);
    this.spawnExpandingRing(pos.clone().add(new Vector3(0, 0.1, 0)), palette[2], 1.0);
  }

  holeTransition() {
    this.transitionTimer = 0.8;
  }

  teleportEffect(pos: Vector3) {
    this.spawnParticleBurst(pos, 40, [0x8844ff, 0xaa66ff, 0xcc88ff, 0x4422cc, 0xffffff], 2.0);
    this.spawnExpandingRing(pos.clone().add(new Vector3(0, 0.05, 0)), 0x8844ff, 1.2);
    this.spawnExpandingRing(pos.clone().add(new Vector3(0, 0.15, 0)), 0xaa66ff, 0.8);
    this.spawnExpandingRing(pos.clone().add(new Vector3(0, 0.25, 0)), 0xcc88ff, 0.6);
  }

  strokeLimitEffect(pos: Vector3) {
    // Subdued red/orange "failed" effect
    this.spawnParticleBurst(pos, 15, [0xff2200, 0xff4400, 0xff6600], 1.5);
    this.spawnExpandingRing(pos.clone().add(new Vector3(0, 0.1, 0)), 0xff4400, 1.0);
  }

  splashEffect(pos: Vector3) {
    // Water splash — blue/cyan particles bursting upward
    this.spawnParticleBurst(pos, 35, [0x0044ff, 0x0088ff, 0x44aaff, 0x88ccff, 0xffffff], 2.0);
    this.spawnExpandingRing(pos.clone().add(new Vector3(0, 0.02, 0)), 0x0066ff, 1.2);
    this.spawnExpandingRing(pos.clone().add(new Vector3(0, 0.05, 0)), 0x44aaff, 0.8);
  }

  // Spawn a short-lived pulsing orb for celebration
  private spawnPulsingOrb(pos: Vector3, color: number, duration: number, size: number) {
    const geo = new SphereGeometry(size, 16, 16);
    const mat = new MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 0.5,
      blending: AdditiveBlending,
    });
    const mesh = new Mesh(geo, mat);
    mesh.position.copy(pos);
    this.effectsGroup.add(mesh);
    this.orbs.push({ mesh, life: duration, maxLife: duration, baseScale: 1, pulseRate: 8 });
  }

  private spawnParticleBurst(
    center: Vector3,
    count: number,
    colors: number[],
    maxLife: number,
  ) {
    for (let i = 0; i < count; i++) {
      const color = colors[Math.floor(Math.random() * colors.length)];
      const size = 0.01 + Math.random() * 0.025;
      const geo = new SphereGeometry(size, 4, 4);
      const mat = new MeshBasicMaterial({
        color,
        transparent: true,
        opacity: 1.0,
        blending: AdditiveBlending,
      });
      const mesh = new Mesh(geo, mat);
      mesh.position.copy(center);

      const velocity = new Vector3(
        (Math.random() - 0.5) * 3,
        Math.random() * 4 + 1,
        (Math.random() - 0.5) * 3,
      );

      const life = maxLife * (0.5 + Math.random() * 0.5);
      this.particles.push({ mesh, velocity, life, maxLife: life });
      this.effectsGroup.add(mesh);
    }
  }

  private spawnExpandingRing(pos: Vector3, color: number, duration: number) {
    const geo = new RingGeometry(0.01, 0.03, 32);
    const mat = new MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 0.8,
      side: DoubleSide,
      blending: AdditiveBlending,
    });
    const mesh = new Mesh(geo, mat);
    mesh.position.copy(pos);
    mesh.rotation.x = -Math.PI / 2;
    this.effectsGroup.add(mesh);
    this.rings.push({ mesh, life: duration, speed: 2.0 });
  }

  private spawnLightColumn(pos: Vector3, color: number, duration: number) {
    const geo = new CylinderGeometry(0.02, 0.15, 5, 8);
    const mat = new MeshBasicMaterial({
      color,
      transparent: true,
      opacity: 0.3,
      blending: AdditiveBlending,
    });
    const mesh = new Mesh(geo, mat);
    mesh.position.copy(pos);
    mesh.position.y += 2.5;
    this.effectsGroup.add(mesh);

    this.particles.push({
      mesh,
      velocity: new Vector3(0, 0, 0),
      life: duration,
      maxLife: duration,
    });
  }

  update(dt: number) {
    // Update particles
    for (let i = this.particles.length - 1; i >= 0; i--) {
      const p = this.particles[i];
      p.life -= dt;

      if (p.life <= 0) {
        this.effectsGroup.remove(p.mesh);
        p.mesh.geometry.dispose();
        (p.mesh.material as MeshBasicMaterial).dispose();
        this.particles.splice(i, 1);
        continue;
      }

      p.mesh.position.add(p.velocity.clone().multiplyScalar(dt));
      p.velocity.y -= 3 * dt;

      const t = p.life / p.maxLife;
      (p.mesh.material as MeshBasicMaterial).opacity = t;
      const scale = 0.3 + t * 0.7;
      p.mesh.scale.setScalar(scale);
    }

    // Update rings
    for (let i = this.rings.length - 1; i >= 0; i--) {
      const r = this.rings[i];
      r.life -= dt;

      if (r.life <= 0) {
        this.effectsGroup.remove(r.mesh);
        r.mesh.geometry.dispose();
        (r.mesh.material as MeshBasicMaterial).dispose();
        this.rings.splice(i, 1);
        continue;
      }

      const scale = r.mesh.scale.x + r.speed * dt;
      r.mesh.scale.setScalar(scale);
      (r.mesh.material as MeshBasicMaterial).opacity *= 0.97;
    }

    // Update pulsing orbs
    for (let i = this.orbs.length - 1; i >= 0; i--) {
      const o = this.orbs[i];
      o.life -= dt;

      if (o.life <= 0) {
        this.effectsGroup.remove(o.mesh);
        o.mesh.geometry.dispose();
        (o.mesh.material as MeshBasicMaterial).dispose();
        this.orbs.splice(i, 1);
        continue;
      }

      const t = o.life / o.maxLife;
      const pulse = 1 + Math.sin(performance.now() * 0.001 * o.pulseRate) * 0.3;
      o.mesh.scale.setScalar(o.baseScale * pulse * (0.5 + t * 0.5));
      (o.mesh.material as MeshBasicMaterial).opacity = t * 0.5;
      o.mesh.position.y += dt * 0.3; // float upward
    }

    // Transition
    if (this.transitionTimer > 0) {
      this.transitionTimer -= dt;
    }
  }
}

/**
 * Holo Golf VR — Audio Manager (Round 3 Overhaul)
 * Procedural audio using Web Audio API for all game sounds.
 * New: course-specific ambient music, stroke limit sound, enhanced effects.
 */

// Course ambient configurations
const COURSE_AMBIENTS = [
  // Course 0: Neon Circuit — clean synth pad, A minor
  { baseFreq: 55, fifthFreq: 82.4, shimmerFreq: 440, lfoRate: 0.3, padType: "sine" as OscillatorType },
  // Course 1: Quantum Field — darker, Bb minor, slower LFO
  { baseFreq: 58.27, fifthFreq: 87.31, shimmerFreq: 466.16, lfoRate: 0.15, padType: "triangle" as OscillatorType },
  // Course 2: Cosmic Abyss — ominous, E minor, deep bass
  { baseFreq: 41.2, fifthFreq: 61.74, shimmerFreq: 329.63, lfoRate: 0.08, padType: "sawtooth" as OscillatorType },
];

export class AudioManager {
  private ctx: AudioContext;
  private masterGain: GainNode;
  private musicGain: GainNode;
  private sfxGain: GainNode;
  private ambientGain: GainNode;
  private initialized = false;

  // Active ambient oscillators for cleanup
  private ambientOscillators: OscillatorNode[] = [];
  private ambientGains: GainNode[] = [];
  private currentCourseIndex = -1;

  constructor() {
    this.ctx = new AudioContext();
    this.masterGain = this.ctx.createGain();
    this.masterGain.gain.value = 0.5;
    this.masterGain.connect(this.ctx.destination);

    this.musicGain = this.ctx.createGain();
    this.musicGain.gain.value = 0.15;
    this.musicGain.connect(this.masterGain);

    this.sfxGain = this.ctx.createGain();
    this.sfxGain.gain.value = 0.7;
    this.sfxGain.connect(this.masterGain);

    this.ambientGain = this.ctx.createGain();
    this.ambientGain.gain.value = 0;
    this.ambientGain.connect(this.musicGain);
  }

  async init() {
    if (this.ctx.state === "suspended") {
      document.addEventListener("click", () => this.ctx.resume(), { once: true });
      document.addEventListener("touchstart", () => this.ctx.resume(), { once: true });
    }
    this.initialized = true;
  }

  // === Ambient Music ===

  playAmbient() {
    this.switchCourseAmbient(0);
  }

  switchCourseAmbient(courseIndex: number) {
    if (courseIndex === this.currentCourseIndex) return;
    this.currentCourseIndex = courseIndex;

    // Fade out existing ambient
    this.stopAmbient();

    const config = COURSE_AMBIENTS[courseIndex] || COURSE_AMBIENTS[0];
    const now = this.ctx.currentTime;

    // Base drone
    const osc1 = this.ctx.createOscillator();
    osc1.type = config.padType;
    osc1.frequency.setValueAtTime(config.baseFreq, now);
    const gain1 = this.ctx.createGain();
    gain1.gain.setValueAtTime(0.25, now);
    osc1.connect(gain1);
    gain1.connect(this.ambientGain);
    osc1.start(now);
    this.ambientOscillators.push(osc1);
    this.ambientGains.push(gain1);

    // Fifth harmony
    const osc2 = this.ctx.createOscillator();
    osc2.type = "sine";
    osc2.frequency.setValueAtTime(config.fifthFreq, now);
    const gain2 = this.ctx.createGain();
    gain2.gain.setValueAtTime(0.12, now);
    osc2.connect(gain2);
    gain2.connect(this.ambientGain);
    osc2.start(now);
    this.ambientOscillators.push(osc2);
    this.ambientGains.push(gain2);

    // High shimmer with LFO
    const osc3 = this.ctx.createOscillator();
    osc3.type = "triangle";
    osc3.frequency.setValueAtTime(config.shimmerFreq, now);
    const gain3 = this.ctx.createGain();
    gain3.gain.setValueAtTime(0.04, now);

    const lfo = this.ctx.createOscillator();
    lfo.frequency.setValueAtTime(config.lfoRate, now);
    const lfoGain = this.ctx.createGain();
    lfoGain.gain.setValueAtTime(20, now);
    lfo.connect(lfoGain);
    lfoGain.connect(osc3.frequency);
    lfo.start(now);

    osc3.connect(gain3);
    gain3.connect(this.ambientGain);
    osc3.start(now);
    this.ambientOscillators.push(osc3, lfo);
    this.ambientGains.push(gain3);

    // Sub bass for courses 1 and 2
    if (courseIndex >= 1) {
      const subOsc = this.ctx.createOscillator();
      subOsc.type = "sine";
      subOsc.frequency.setValueAtTime(config.baseFreq / 2, now);
      const subGain = this.ctx.createGain();
      subGain.gain.setValueAtTime(0.15, now);
      subOsc.connect(subGain);
      subGain.connect(this.ambientGain);
      subOsc.start(now);
      this.ambientOscillators.push(subOsc);
      this.ambientGains.push(subGain);
    }

    // Fade in
    this.ambientGain.gain.cancelScheduledValues(now);
    this.ambientGain.gain.setValueAtTime(0, now);
    this.ambientGain.gain.linearRampToValueAtTime(1.0, now + 2);
  }

  stopAmbient() {
    const now = this.ctx.currentTime;
    // Fade out existing
    this.ambientGain.gain.cancelScheduledValues(now);
    this.ambientGain.gain.linearRampToValueAtTime(0, now + 0.5);

    // Stop and disconnect old oscillators
    setTimeout(() => {
      for (const osc of this.ambientOscillators) {
        try { osc.stop(); } catch {}
      }
      for (const g of this.ambientGains) {
        try { g.disconnect(); } catch {}
      }
      this.ambientOscillators = [];
      this.ambientGains = [];
    }, 600);
  }

  // === Sound Effects ===

  playPutt() {
    this.playTone(220, 0.08, 0.4, "sine");
    this.playTone(330, 0.05, 0.2, "triangle", 0.02);
  }

  playSwing(power: number) {
    const now = this.ctx.currentTime;
    const duration = 0.15 + power * 0.1;

    const bufferSize = Math.floor(this.ctx.sampleRate * duration);
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * (1 - i / bufferSize);
    }

    const src = this.ctx.createBufferSource();
    src.buffer = buffer;

    const filter = this.ctx.createBiquadFilter();
    filter.type = "bandpass";
    filter.frequency.setValueAtTime(800 + power * 2000, now);
    filter.frequency.exponentialRampToValueAtTime(200, now + duration);
    filter.Q.setValueAtTime(2, now);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.3 * power, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + duration);

    src.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain);
    src.start(now);
  }

  playBounce(force: number) {
    const vol = Math.min(force * 0.5, 0.4);
    this.playTone(180 + force * 200, 0.06, vol, "sine");
  }

  playWallBounce(speed: number) {
    const vol = Math.min(speed * 0.3, 0.5);
    this.playTone(400, 0.04, vol, "square");
    this.playTone(300, 0.06, vol * 0.5, "sine", 0.02);
  }

  playBumperHit(speed: number) {
    const vol = Math.min(speed * 0.3, 0.6);
    this.playTone(600, 0.08, vol, "sine");
    this.playTone(900, 0.06, vol * 0.6, "triangle", 0.03);
    this.playTone(1200, 0.04, vol * 0.3, "sine", 0.06);
  }

  playTeleport() {
    const notes = [800, 1200, 1600, 2400];
    notes.forEach((freq, i) => {
      this.playTone(freq, 0.12, 0.25, "sine", i * 0.04);
    });
    [2400, 1600, 1200, 800].forEach((freq, i) => {
      this.playTone(freq, 0.08, 0.15, "triangle", 0.2 + i * 0.03);
    });
  }

  playWindZone() {
    const now = this.ctx.currentTime;
    const bufferSize = Math.floor(this.ctx.sampleRate * 0.3);
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      data[i] = (Math.random() * 2 - 1) * (1 - i / bufferSize) * 0.3;
    }
    const src = this.ctx.createBufferSource();
    src.buffer = buffer;
    const filter = this.ctx.createBiquadFilter();
    filter.type = "bandpass";
    filter.frequency.setValueAtTime(400, now);
    filter.Q.setValueAtTime(1, now);
    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.15, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.3);
    src.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain);
    src.start(now);
  }

  playHoleStart() {
    const notes = [262, 330, 392, 523]; // C4 E4 G4 C5
    notes.forEach((freq, i) => {
      this.playTone(freq, 0.15, 0.2, "triangle", i * 0.08);
    });
  }

  playHoleComplete() {
    const notes = [392, 494, 523, 659]; // G4 B4 C5 E5
    notes.forEach((freq, i) => {
      this.playTone(freq, 0.2, 0.25, "triangle", i * 0.1);
    });
  }

  playHoleInOne() {
    const notes = [523, 659, 784, 1047, 784, 1047];
    notes.forEach((freq, i) => {
      this.playTone(freq, 0.3, 0.35, "triangle", i * 0.12);
    });
    setTimeout(() => this.playSparkle(), 600);
  }

  playUnderPar() {
    const notes = [523, 659, 784];
    notes.forEach((freq, i) => {
      this.playTone(freq, 0.25, 0.3, "triangle", i * 0.1);
    });
  }

  playCourseComplete() {
    const notes = [262, 330, 392, 523, 659, 784, 1047];
    notes.forEach((freq, i) => {
      this.playTone(freq, 0.4, 0.3, "triangle", i * 0.15);
    });
    setTimeout(() => this.playSparkle(), 800);
    setTimeout(() => this.playSparkle(), 1200);
  }

  playStrokeLimit() {
    // Descending "wah wah" sound
    this.playTone(400, 0.3, 0.25, "triangle");
    this.playTone(350, 0.3, 0.2, "triangle", 0.15);
    this.playTone(280, 0.4, 0.25, "triangle", 0.3);
  }

  playSplash() {
    // Water splash effect — burst of filtered noise + descending tone
    const now = this.ctx.currentTime;
    const bufferSize = Math.floor(this.ctx.sampleRate * 0.4);
    const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
    const data = buffer.getChannelData(0);
    for (let i = 0; i < bufferSize; i++) {
      const env = Math.exp(-i / (bufferSize * 0.15));
      data[i] = (Math.random() * 2 - 1) * env * 0.5;
    }
    const src = this.ctx.createBufferSource();
    src.buffer = buffer;
    const filter = this.ctx.createBiquadFilter();
    filter.type = "lowpass";
    filter.frequency.setValueAtTime(2000, now);
    filter.frequency.exponentialRampToValueAtTime(300, now + 0.3);
    filter.Q.setValueAtTime(1.5, now);
    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(0.35, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + 0.4);
    src.connect(filter);
    filter.connect(gain);
    gain.connect(this.sfxGain);
    src.start(now);

    // Watery bubbling tones
    this.playTone(200, 0.15, 0.15, "sine", 0.05);
    this.playTone(280, 0.12, 0.1, "sine", 0.1);
    this.playTone(160, 0.2, 0.12, "sine", 0.15);
  }

  playOOB() {
    // Out-of-bounds alert — short descending warning
    this.playTone(600, 0.15, 0.2, "square");
    this.playTone(400, 0.2, 0.25, "square", 0.1);
    this.playTone(250, 0.3, 0.2, "square", 0.2);
  }

  playReset() {
    this.playTone(400, 0.1, 0.15, "sine");
    this.playTone(300, 0.1, 0.15, "sine", 0.05);
  }

  playMenuSelect() {
    this.playTone(600, 0.08, 0.2, "triangle");
  }

  playMenuHover() {
    this.playTone(800, 0.04, 0.1, "sine");
  }

  private playSparkle() {
    for (let i = 0; i < 8; i++) {
      const freq = 2000 + Math.random() * 4000;
      this.playTone(freq, 0.05, 0.1, "sine", i * 0.03 + Math.random() * 0.02);
    }
  }

  private playTone(
    freq: number,
    duration: number,
    volume: number,
    type: OscillatorType = "sine",
    delay = 0,
  ) {
    if (!this.initialized) return;
    const now = this.ctx.currentTime + delay;

    const osc = this.ctx.createOscillator();
    osc.type = type;
    osc.frequency.setValueAtTime(freq, now);

    const gain = this.ctx.createGain();
    gain.gain.setValueAtTime(volume, now);
    gain.gain.exponentialRampToValueAtTime(0.001, now + duration);

    osc.connect(gain);
    gain.connect(this.sfxGain);
    osc.start(now);
    osc.stop(now + duration + 0.01);
  }

  setMasterVolume(vol: number) {
    this.masterGain.gain.setValueAtTime(Math.max(0, Math.min(1, vol)), this.ctx.currentTime);
  }

  setSFXVolume(vol: number) {
    this.sfxGain.gain.setValueAtTime(Math.max(0, Math.min(1, vol)), this.ctx.currentTime);
  }

  setMusicVolume(vol: number) {
    this.musicGain.gain.setValueAtTime(Math.max(0, Math.min(1, vol)), this.ctx.currentTime);
  }
}

/**
 * Holo Golf VR — Ball Controller
 * Custom physics for the golf ball: velocity, friction, slope, walls,
 * bumper/obstacle collision, hole capture, and trail effects.
 */
import {
  World,
  Vector3,
  Mesh,
  SphereGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Group,
  Color,
  EdgesGeometry,
  LineSegments,
  LineBasicMaterial,
  AdditiveBlending,
  PointLight,
  RingGeometry,
  DoubleSide,
} from "@iwsdk/core";
import { AudioManager } from "./audio";

const BALL_RADIUS = 0.025;
const FRICTION = 0.97;
const SLOPE_FORCE = 4.0;
const MIN_VELOCITY = 0.005;
const MAX_VELOCITY = 12.0;
const WALL_BOUNCE = 0.65;
const BUMPER_BOUNCE = 1.8;
const GRAVITY = -9.8;

export interface BumperCollider {
  position: Vector3;
  radius: number;
  mesh?: any;
}

export interface ObstacleCollider {
  type: "windmill_arm" | "moving_wall";
  mesh: any;
  getWorldBounds: () => { min: Vector3; max: Vector3; normal: Vector3 };
}

export class BallController {
  position = new Vector3(0, 0.05, 0);
  velocity = new Vector3(0, 0, 0);
  isActive = false;
  private mesh: Mesh;
  private glowMesh: Mesh;
  private trailGroup: Group;
  private light: PointLight;
  private world: World;
  private audio: AudioManager;
  private sinking = false;
  private sinkTarget = new Vector3();
  private sinkTimer = 0;
  private trailPositions: Vector3[] = [];
  private trailPool: Mesh[] = [];
  private trailActiveCount = 0;
  private bounceCount = 0;
  private onFloor = true;
  private floorY = 0.05;
  private stopped = true;

  // Shadow
  private shadow: Mesh;

  // Out-of-bounds callback
  onOutOfBounds: (() => void) | null = null;

  // Special zone effects
  private windForce = new Vector3();
  private frictionOverride: number | null = null;

  // Course-themed trail colors
  private trailColor1 = new Color(0x00ffff);
  private trailColor2 = new Color(0xff4488);

  constructor(world: World, audio: AudioManager) {
    this.world = world;
    this.audio = audio;

    // Main ball mesh — glowing cyan sphere
    const ballGeo = new SphereGeometry(BALL_RADIUS, 16, 16);
    const ballMat = new MeshStandardMaterial({
      color: new Color(0x00ffff),
      emissive: new Color(0x00aaaa),
      emissiveIntensity: 1.5,
      metalness: 0.3,
      roughness: 0.1,
    });
    this.mesh = new Mesh(ballGeo, ballMat);

    // Wireframe glow
    const edgesGeo = new EdgesGeometry(ballGeo);
    this.glowMesh = new Mesh(); // placeholder
    const wireframe = new LineSegments(
      edgesGeo,
      new LineBasicMaterial({ color: 0x00ffff, transparent: true, opacity: 0.6 }),
    );
    this.mesh.add(wireframe);

    // Outer glow
    const glowGeo = new SphereGeometry(BALL_RADIUS * 1.6, 12, 12);
    const glowMat = new MeshBasicMaterial({
      color: new Color(0x00ffff),
      transparent: true,
      opacity: 0.15,
      blending: AdditiveBlending,
    });
    this.glowMesh = new Mesh(glowGeo, glowMat);
    this.mesh.add(this.glowMesh);

    // Ground ring indicator
    const ringGeo = new RingGeometry(BALL_RADIUS * 1.5, BALL_RADIUS * 2.5, 24);
    const ringMat = new MeshBasicMaterial({
      color: 0x00ffff,
      transparent: true,
      opacity: 0.3,
      side: DoubleSide,
      blending: AdditiveBlending,
    });
    const ring = new Mesh(ringGeo, ringMat);
    ring.rotation.x = -Math.PI / 2;
    ring.position.y = -BALL_RADIUS + 0.001;
    this.mesh.add(ring);

    // Point light
    this.light = new PointLight(0x00ffff, 0.8, 3);
    this.mesh.add(this.light);

    // Shadow (projected on ground)
    const shadowGeo = new SphereGeometry(BALL_RADIUS * 2.5, 12, 1);
    const shadowMat = new MeshBasicMaterial({
      color: 0x000000,
      transparent: true,
      opacity: 0.25,
    });
    this.shadow = new Mesh(shadowGeo, shadowMat);
    this.shadow.scale.set(1, 0.02, 1);
    world.scene.add(this.shadow);
    this.shadow.visible = false;

    // Trail group + pre-allocated pool
    this.trailGroup = new Group();
    world.scene.add(this.trailGroup);
    this.initTrailPool(50);

    world.scene.add(this.mesh);
    this.mesh.visible = false;
  }

  reset(pos: Vector3) {
    this.position.copy(pos);
    this.position.y = pos.y + BALL_RADIUS;
    this.velocity.set(0, 0, 0);
    this.mesh.position.copy(this.position);
    this.mesh.visible = true;
    this.mesh.scale.setScalar(1);
    this.isActive = true;
    this.sinking = false;
    this.stopped = true;
    this.bounceCount = 0;
    this.floorY = pos.y + BALL_RADIUS;
    this.windForce.set(0, 0, 0);
    this.frictionOverride = null;
    this.clearTrail();

    // Update shadow
    this.shadow.visible = true;
    this.shadow.position.set(pos.x, pos.y + 0.002, pos.z);
  }

  hit(direction: Vector3, power: number) {
    if (!this.isActive || this.sinking) return;
    const force = direction.clone().normalize().multiplyScalar(power);
    force.y = Math.max(force.y, power * 0.05); // tiny upward lift
    this.velocity.copy(force);
    this.stopped = false;
    this.bounceCount = 0;
  }

  sinkIntoHole(holePos: Vector3) {
    this.sinking = true;
    this.sinkTarget.copy(holePos);
    this.sinkTarget.y -= 0.1;
    this.sinkTimer = 0;
    this.velocity.set(0, 0, 0);
    this.shadow.visible = false;
  }

  isStopped(): boolean {
    return this.stopped && !this.sinking;
  }

  setWindForce(force: Vector3) {
    this.windForce.copy(force);
  }

  setFrictionOverride(friction: number | null) {
    this.frictionOverride = friction;
  }

  setCourseTheme(courseIndex: number) {
    const themes = [
      { c1: 0x00ffff, c2: 0xff4488 },  // Neon Circuit
      { c1: 0xff44aa, c2: 0x8844ff },  // Quantum Field
      { c1: 0xff6600, c2: 0xffaa00 },  // Cosmic Abyss
    ];
    const theme = themes[courseIndex] || themes[0];
    this.trailColor1.set(theme.c1);
    this.trailColor2.set(theme.c2);
  }

  update(dt: number) {
    if (!this.isActive) return;

    if (this.sinking) {
      this.sinkTimer += dt;
      const t = Math.min(this.sinkTimer / 0.5, 1);
      this.position.lerp(this.sinkTarget, t * 0.15);
      const scale = 1 - t * 0.8;
      this.mesh.scale.setScalar(Math.max(scale, 0.01));
      this.mesh.position.copy(this.position);
      if (t >= 1) {
        this.mesh.visible = false;
        this.isActive = false;
      }
      return;
    }

    if (this.stopped) {
      this.mesh.position.copy(this.position);
      return;
    }

    // Apply friction (use override if in special zone)
    const fric = this.frictionOverride ?? FRICTION;
    this.velocity.x *= fric;
    this.velocity.z *= fric;

    // Apply wind force
    if (this.windForce.lengthSq() > 0) {
      this.velocity.add(this.windForce.clone().multiplyScalar(dt));
    }

    // Gravity
    if (!this.onFloor) {
      this.velocity.y += GRAVITY * dt;
    }

    // Clamp velocity
    const speed = this.velocity.length();
    if (speed > MAX_VELOCITY) {
      this.velocity.normalize().multiplyScalar(MAX_VELOCITY);
    }

    // Move ball
    this.position.add(this.velocity.clone().multiplyScalar(dt));

    // Floor collision
    if (this.position.y <= this.floorY) {
      this.position.y = this.floorY;
      if (this.velocity.y < -0.3) {
        this.velocity.y *= -WALL_BOUNCE * 0.5;
        this.bounceCount++;
        if (this.bounceCount > 3) {
          this.velocity.y = 0;
        }
        this.audio.playBounce(Math.abs(this.velocity.y));
      } else {
        this.velocity.y = 0;
      }
      this.onFloor = true;
    } else {
      this.onFloor = false;
    }

    // Wall collisions
    this.checkWallCollisions();

    // Bumper collisions
    this.checkBumperCollisions();

    // Check if ball fell off course (OOB)
    if (this.position.y < -3) {
      this.velocity.set(0, 0, 0);
      this.stopped = true;
      if (this.onOutOfBounds) {
        this.onOutOfBounds();
        return;
      }
    }

    // Stop check
    if (speed < MIN_VELOCITY && this.onFloor) {
      this.velocity.set(0, 0, 0);
      this.stopped = true;
    }

    // Update mesh
    this.mesh.position.copy(this.position);

    // Update shadow
    this.shadow.position.set(this.position.x, this.floorY - BALL_RADIUS + 0.003, this.position.z);
    const shadowHeight = Math.max(0, this.position.y - (this.floorY - BALL_RADIUS));
    const shadowScale = Math.max(0.3, 1 - shadowHeight * 0.5);
    this.shadow.scale.set(shadowScale, 0.02, shadowScale);
    (this.shadow.material as MeshBasicMaterial).opacity = Math.max(0.05, 0.25 - shadowHeight * 0.1);

    // Glow pulse
    const pulse = 0.12 + Math.sin(performance.now() * 0.004) * 0.05;
    (this.glowMesh.material as MeshBasicMaterial).opacity = pulse;
    this.light.intensity = 0.5 + speed * 0.3;

    // Update trail (optimized pool)
    this.updateTrail();
  }

  private checkWallCollisions() {
    const walls = (this.world as any).__holoGolfWalls as Array<{
      normal: Vector3;
      point: Vector3;
      min: Vector3;
      max: Vector3;
    }>;
    if (!walls) return;

    for (const wall of walls) {
      const dist = this.position.clone().sub(wall.point).dot(wall.normal);
      if (dist < BALL_RADIUS) {
        const p = this.position;
        if (
          p.x >= wall.min.x - BALL_RADIUS &&
          p.x <= wall.max.x + BALL_RADIUS &&
          p.y >= wall.min.y - BALL_RADIUS &&
          p.y <= wall.max.y + BALL_RADIUS &&
          p.z >= wall.min.z - BALL_RADIUS &&
          p.z <= wall.max.z + BALL_RADIUS
        ) {
          this.position.add(wall.normal.clone().multiplyScalar(BALL_RADIUS - dist));
          const dot = this.velocity.dot(wall.normal);
          if (dot < 0) {
            this.velocity.sub(wall.normal.clone().multiplyScalar(2 * dot));
            this.velocity.multiplyScalar(WALL_BOUNCE);
            this.audio.playWallBounce(this.velocity.length());
          }
        }
      }
    }
  }

  private checkBumperCollisions() {
    const bumpers = (this.world as any).__holoGolfBumpers as BumperCollider[] | undefined;
    if (!bumpers) return;

    for (const bumper of bumpers) {
      const dx = this.position.x - bumper.position.x;
      const dz = this.position.z - bumper.position.z;
      const dist2D = Math.sqrt(dx * dx + dz * dz);
      const minDist = BALL_RADIUS + bumper.radius;

      if (dist2D < minDist && Math.abs(this.position.y - bumper.position.y) < 0.15) {
        // Push ball out
        if (dist2D > 0.001) {
          const nx = dx / dist2D;
          const nz = dz / dist2D;
          this.position.x = bumper.position.x + nx * minDist;
          this.position.z = bumper.position.z + nz * minDist;

          // Reflect and boost velocity
          const normal = new Vector3(nx, 0, nz);
          const dot = this.velocity.dot(normal);
          if (dot < 0) {
            this.velocity.sub(normal.multiplyScalar(2 * dot));
            this.velocity.multiplyScalar(BUMPER_BOUNCE);
            // Clamp after boost
            if (this.velocity.length() > MAX_VELOCITY) {
              this.velocity.normalize().multiplyScalar(MAX_VELOCITY);
            }
            this.audio.playBumperHit(this.velocity.length());
          }
        }
      }
    }
  }

  // === Trail system (object pool) ===

  private initTrailPool(count: number) {
    const geo = new SphereGeometry(BALL_RADIUS * 0.5, 4, 4);
    for (let i = 0; i < count; i++) {
      const mat = new MeshBasicMaterial({
        color: 0x00ffff,
        transparent: true,
        opacity: 0,
        blending: AdditiveBlending,
      });
      const dot = new Mesh(geo, mat);
      dot.visible = false;
      this.trailGroup.add(dot);
      this.trailPool.push(dot);
    }
  }

  private updateTrail() {
    if (this.stopped) {
      // Fade out existing trail
      for (let i = 0; i < this.trailActiveCount; i++) {
        const dot = this.trailPool[i];
        const mat = dot.material as MeshBasicMaterial;
        mat.opacity *= 0.9;
        if (mat.opacity < 0.01) {
          dot.visible = false;
        }
      }
      return;
    }

    const speed = this.velocity.length();
    if (speed < 0.1) return;

    // Add current position
    this.trailPositions.push(this.position.clone());
    if (this.trailPositions.length > this.trailPool.length) {
      this.trailPositions.shift();
    }

    // Update pool meshes
    this.trailActiveCount = this.trailPositions.length;
    for (let i = 0; i < this.trailPool.length; i++) {
      const dot = this.trailPool[i];
      if (i < this.trailPositions.length) {
        const t = i / this.trailPositions.length;
        dot.position.copy(this.trailPositions[i]);
        dot.scale.setScalar(t);
        const mat = dot.material as MeshBasicMaterial;
        mat.opacity = t * 0.4;
        mat.color.lerpColors(this.trailColor1, this.trailColor2, t);
        dot.visible = true;
      } else {
        dot.visible = false;
      }
    }
  }

  private clearTrail() {
    this.trailPositions = [];
    this.trailActiveCount = 0;
    for (const dot of this.trailPool) {
      dot.visible = false;
    }
  }
}

/**
 * Holo Golf VR — UI Manager (Round 3 Overhaul)
 * Title screen, course select, settings, and game-over overlays.
 * Full XR controller navigation: handleNavNext/Prev for thumbstick, handleBack for B.
 * Course-specific color theming.
 */
import { World } from "@iwsdk/core";
import { GameManager, GameState } from "./game";
import { AudioManager } from "./audio";
import { PracticeMode } from "./practice";

// Course color themes
const COURSE_THEMES = [
  { primary: "#00ffff", secondary: "#0088aa", accent: "#44ff88", name: "Neon Circuit", emoji: "🟢" },
  { primary: "#ff44aa", secondary: "#cc2266", accent: "#8844ff", name: "Quantum Field", emoji: "🟣" },
  { primary: "#ff6600", secondary: "#cc4400", accent: "#ffaa00", name: "Cosmic Abyss", emoji: "🔴" },
];

export class UIManager {
  private world: World;
  private game: GameManager;
  private audio: AudioManager;
  private overlay: HTMLDivElement;
  currentScreen: string = "";

  // XR navigation state
  private focusIndex = 0;
  private focusableCount = 0;
  private focusableIds: string[] = [];

  // Practice mode
  practiceMode: PracticeMode | null = null;

  constructor(world: World, game: GameManager, audio: AudioManager) {
    this.world = world;
    this.game = game;
    this.audio = audio;

    this.overlay = document.createElement("div");
    this.overlay.id = "holo-golf-ui";
    this.overlay.style.cssText = `
      position: fixed; top: 0; left: 0; width: 100%; height: 100%;
      pointer-events: none; z-index: 100; font-family: 'Courier New', monospace;
    `;
    document.body.appendChild(this.overlay);

    game.onStateChange((state) => {
      if (state === GameState.COURSE_COMPLETE) {
        this.showCourseComplete();
      }
      if (state === GameState.PAUSED) {
        this.showPauseMenu();
      }
    });
  }

  showTitle() {
    this.currentScreen = "title";
    this.focusableIds = ["btn-play", "btn-leaderboard", "btn-settings"];
    this.focusIndex = 0;
    this.focusableCount = 3;

    this.overlay.innerHTML = `
      <div style="
        display: flex; flex-direction: column; align-items: center; justify-content: center;
        width: 100%; height: 100%; pointer-events: auto;
        background: radial-gradient(ellipse at center, rgba(0,20,40,0.9) 0%, rgba(0,0,0,0.95) 100%);
      ">
        <div style="text-align: center;">
          <h1 style="
            font-size: 72px; color: #00ffff; margin: 0; letter-spacing: 8px;
            text-shadow: 0 0 20px #00ffff, 0 0 40px #0088aa, 0 0 80px #004466;
          ">HOLO GOLF</h1>
          <div style="
            font-size: 18px; color: #4488aa; margin-top: 8px; letter-spacing: 6px;
          ">VIRTUAL REALITY MINI GOLF</div>
          <div style="
            width: 300px; height: 2px; margin: 24px auto;
            background: linear-gradient(90deg, transparent, #00ffff, transparent);
          "></div>
          <div style="margin-top: 40px;">
            <button id="btn-play" style="${this.buttonStyle()}" data-focus="0">
              ▶ PLAY
            </button>
          </div>
          <div style="margin-top: 15px;">
            <button id="btn-leaderboard" style="${this.buttonStyle('#ffaa00', '#cc8800')}" data-focus="1">
              🏆 LEADERBOARD
            </button>
          </div>
          <div style="margin-top: 15px;">
            <button id="btn-settings" style="${this.buttonStyle('#ff4488', '#cc2266')}" data-focus="2">
              ⚙ SETTINGS
            </button>
          </div>
          <div style="
            margin-top: 50px; color: #334455; font-size: 12px; letter-spacing: 2px;
          ">
            MOUSE: CLICK & DRAG TO AIM AND PUTT<br>
            VR: SWING CONTROLLER OR PRESS TRIGGER<br>
            <span style="color: #224455; font-size: 11px;">GRIP = POWER BOOST · LEFT STICK = CAMERA · ESC = PAUSE</span>
          </div>
        </div>
      </div>
    `;

    this.overlay.querySelector("#btn-play")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      this.showCourseSelect();
    });

    this.overlay.querySelector("#btn-leaderboard")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      // Dispatch a custom event that browserinput listens for
      window.dispatchEvent(new CustomEvent("holo-golf-show-leaderboard"));
    });

    this.overlay.querySelector("#btn-settings")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      this.showSettings();
    });

    this.updateFocusHighlight();
  }

  showCourseSelect() {
    this.currentScreen = "course_select";
    this.focusableIds = ["course-0", "course-1", "course-2", "btn-back"];
    this.focusIndex = 0;
    this.focusableCount = 4;

    this.overlay.innerHTML = `
      <div style="
        display: flex; flex-direction: column; align-items: center; justify-content: center;
        width: 100%; height: 100%; pointer-events: auto;
        background: radial-gradient(ellipse at center, rgba(0,20,40,0.85) 0%, rgba(0,0,0,0.95) 100%);
      ">
        <h2 style="color: #00ffff; font-size: 36px; letter-spacing: 4px; margin-bottom: 30px;
          text-shadow: 0 0 15px #00ffff;">SELECT COURSE</h2>

        <div style="display: flex; gap: 20px; flex-wrap: wrap; justify-content: center;">
          ${COURSE_THEMES.map((theme, i) => `
            <div id="course-${i}" class="course-card" style="${this.courseCardStyle(true, i === this.focusIndex)}" data-focus="${i}">
              <div style="font-size: 40px; margin-bottom: 10px;">${theme.emoji}</div>
              <div style="font-size: 20px; color: ${theme.primary}; font-weight: bold;">${theme.name}</div>
              <div style="font-size: 12px; color: #6688aa; margin-top: 6px;">9 Holes • ${i === 0 ? 'Easy-Medium' : i === 1 ? 'Medium-Hard' : 'Expert'}</div>
              ${i === 2 ? '<div style="font-size: 11px; color: #ff6644; margin-top: 4px;">🌀 Teleporters • 💨 Wind • ❄️ Ice</div>' : ''}
              <div style="font-size: 11px; color: #445566; margin-top: 4px;">
                ${this.getBestScoreText(i)}
              </div>
              <div id="practice-btn-${i}" style="font-size: 10px; color: #44ff88; margin-top: 8px; cursor: pointer; letter-spacing: 1px;">
                🏋 PRACTICE
              </div>
            </div>
          `).join('')}
        </div>

        <button id="btn-back" style="${this.buttonStyle('#445566', '#334455')}; margin-top: 30px;" data-focus="3">
          ← BACK
        </button>

        <div style="margin-top: 20px; color: #223344; font-size: 11px; letter-spacing: 1px;">
          VR: THUMBSTICK ◄► TO BROWSE · TRIGGER TO SELECT · B TO GO BACK
        </div>
      </div>
    `;

    for (let i = 0; i < 3; i++) {
      this.overlay.querySelector(`#course-${i}`)?.addEventListener("click", (e) => {
        // Ignore if clicking the practice button
        if ((e.target as HTMLElement).id?.startsWith("practice-btn")) return;
        this.audio.playMenuSelect();
        this.hideUI();
        this.game.startCourse(i);
      });
      this.overlay.querySelector(`#practice-btn-${i}`)?.addEventListener("click", (e) => {
        e.stopPropagation();
        this.audio.playMenuSelect();
        if (this.practiceMode) {
          this.practiceMode.show(i);
        }
      });
    }

    this.overlay.querySelector("#btn-back")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      this.showTitle();
    });

    this.updateFocusHighlight();
  }

  showSettings() {
    this.currentScreen = "settings";
    this.focusableIds = ["btn-back"];
    this.focusIndex = 0;
    this.focusableCount = 1;

    this.overlay.innerHTML = `
      <div style="
        display: flex; flex-direction: column; align-items: center; justify-content: center;
        width: 100%; height: 100%; pointer-events: auto;
        background: radial-gradient(ellipse at center, rgba(0,20,40,0.85) 0%, rgba(0,0,0,0.95) 100%);
      ">
        <h2 style="color: #00ffff; font-size: 36px; letter-spacing: 4px; margin-bottom: 30px;
          text-shadow: 0 0 15px #00ffff;">SETTINGS</h2>

        <div style="width: 350px;">
          <div style="margin-bottom: 20px;">
            <label style="color: #6688aa; font-size: 14px;">MASTER VOLUME</label>
            <input id="vol-master" type="range" min="0" max="100" value="50"
              style="${this.sliderStyle()}">
          </div>
          <div style="margin-bottom: 20px;">
            <label style="color: #6688aa; font-size: 14px;">MUSIC</label>
            <input id="vol-music" type="range" min="0" max="100" value="15"
              style="${this.sliderStyle()}">
          </div>
          <div style="margin-bottom: 20px;">
            <label style="color: #6688aa; font-size: 14px;">SFX</label>
            <input id="vol-sfx" type="range" min="0" max="100" value="70"
              style="${this.sliderStyle()}">
          </div>
        </div>

        <button id="btn-back" style="${this.buttonStyle('#445566', '#334455')}; margin-top: 20px;" data-focus="0">
          ← BACK
        </button>
      </div>
    `;

    this.overlay.querySelector("#vol-master")?.addEventListener("input", (e) => {
      this.audio.setMasterVolume(parseInt((e.target as HTMLInputElement).value) / 100);
    });
    this.overlay.querySelector("#vol-music")?.addEventListener("input", (e) => {
      this.audio.setMusicVolume(parseInt((e.target as HTMLInputElement).value) / 100);
    });
    this.overlay.querySelector("#vol-sfx")?.addEventListener("input", (e) => {
      this.audio.setSFXVolume(parseInt((e.target as HTMLInputElement).value) / 100);
    });
    this.overlay.querySelector("#btn-back")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      this.showTitle();
    });
  }

  showCourseComplete() {
    this.currentScreen = "complete";
    this.focusableIds = ["btn-replay", "btn-menu"];
    this.focusIndex = 0;
    this.focusableCount = 2;

    const score = this.game.courseScore;
    const totalPar = score.holes.reduce((s, h) => s + h.par, 0);
    const diff = score.totalStrokes - totalPar;
    const holeInOnes = score.holes.filter((h) => h.holeInOne).length;
    const theme = COURSE_THEMES[this.game.currentCourseIndex] || COURSE_THEMES[0];

    this.overlay.innerHTML = `
      <div style="
        display: flex; flex-direction: column; align-items: center; justify-content: center;
        width: 100%; height: 100%; pointer-events: auto;
        background: radial-gradient(ellipse at center, rgba(0,20,40,0.9) 0%, rgba(0,0,0,0.95) 100%);
      ">
        <h2 style="color: #ffff00; font-size: 42px; letter-spacing: 4px;
          text-shadow: 0 0 20px #ffff00, 0 0 40px #ff8800;">
          🏆 COURSE COMPLETE!
        </h2>

        <div style="margin-top: 10px; font-size: 14px; color: ${theme.primary}; letter-spacing: 3px;">
          ${theme.name.toUpperCase()}
        </div>

        <div style="margin-top: 20px; text-align: center;">
          <div style="font-size: 52px; color: #ffffff; font-weight: bold;">
            ${score.totalStrokes}
          </div>
          <div style="font-size: 16px; color: #6688aa; margin-top: 5px;">TOTAL STROKES</div>
          <div style="font-size: 24px; color: ${diff <= 0 ? '#00ff88' : '#ff8844'}; margin-top: 10px;">
            ${diff === 0 ? 'Even Par' : diff < 0 ? `${diff} Under Par` : `+${diff} Over Par`}
          </div>
          ${holeInOnes > 0 ? `
            <div style="font-size: 20px; color: #ffff00; margin-top: 10px;">
              ⭐ ${holeInOnes} Hole-in-One${holeInOnes > 1 ? 's' : ''}!
            </div>
          ` : ''}
        </div>

        <div style="margin-top: 15px; padding: 12px 20px; border: 1px solid #223344; background: rgba(0,10,20,0.6); font-size: 12px; color: #6688aa;">
          ${this.buildMiniResultTable(score)}
        </div>

        <div style="margin-top: 30px; display: flex; gap: 15px;">
          <button id="btn-replay" style="${this.buttonStyle(theme.primary, theme.secondary)}" data-focus="0">
            🔄 REPLAY
          </button>
          <button id="btn-menu" style="${this.buttonStyle('#ff4488', '#cc2266')}" data-focus="1">
            🏠 MENU
          </button>
        </div>

        <div style="margin-top: 15px; color: #223344; font-size: 11px;">
          VR: TRIGGER TO SELECT · THUMBSTICK ◄► TO BROWSE
        </div>
      </div>
    `;

    this.overlay.querySelector("#btn-replay")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      this.hideUI();
      this.game.startCourse(this.game.currentCourseIndex);
    });

    this.overlay.querySelector("#btn-menu")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      this.showTitle();
    });

    this.updateFocusHighlight();
  }

  showPauseMenu() {
    this.currentScreen = "paused";
    this.focusableIds = ["btn-resume", "btn-quit"];
    this.focusIndex = 0;
    this.focusableCount = 2;

    const theme = COURSE_THEMES[this.game.currentCourseIndex] || COURSE_THEMES[0];

    this.overlay.innerHTML = `
      <div style="
        display: flex; flex-direction: column; align-items: center; justify-content: center;
        width: 100%; height: 100%; pointer-events: auto;
        background: radial-gradient(ellipse at center, rgba(0,15,30,0.92) 0%, rgba(0,0,0,0.96) 100%);
      ">
        <h2 style="color: ${theme.primary}; font-size: 42px; letter-spacing: 6px; margin-bottom: 10px;
          text-shadow: 0 0 20px ${theme.primary};">
          ⏸ PAUSED
        </h2>

        <div style="margin-top: 10px; font-size: 13px; color: #445566; letter-spacing: 2px;">
          ${theme.name.toUpperCase()} · HOLE ${this.game.currentHoleIndex + 1}
        </div>

        <div style="
          margin-top: 20px; padding: 15px 30px;
          border: 1px solid #223344; background: rgba(0,10,20,0.5);
          text-align: center;
        ">
          <div style="font-size: 14px; color: #6688aa;">
            Strokes: <span style="color: #ffffff; font-weight: bold;">${this.game.currentStrokes}</span> / ${10}
          </div>
          <div style="font-size: 12px; color: #445566; margin-top: 4px;">
            Course total: ${this.game.courseScore.totalStrokes + this.game.currentStrokes}
          </div>
        </div>

        <div style="margin-top: 35px;">
          <button id="btn-resume" style="${this.buttonStyle(theme.primary, theme.secondary)}" data-focus="0">
            ▶ RESUME
          </button>
        </div>
        <div style="margin-top: 15px;">
          <button id="btn-quit" style="${this.buttonStyle('#ff4488', '#cc2266')}" data-focus="1">
            ✕ QUIT TO MENU
          </button>
        </div>

        <div style="margin-top: 30px; color: #223344; font-size: 11px; letter-spacing: 1px;">
          ESC TO RESUME · VR: B BUTTON
        </div>
      </div>
    `;

    this.overlay.querySelector("#btn-resume")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      this.hideUI();
      this.game.resume();
    });

    this.overlay.querySelector("#btn-quit")?.addEventListener("click", () => {
      this.audio.playMenuSelect();
      this.game.resume(); // restore state first
      this.showTitle();
    });

    this.updateFocusHighlight();
  }

  // === XR Controller Navigation ===

  handleSelect() {
    if (this.currentScreen === "title") {
      if (this.focusIndex === 0) {
        this.showCourseSelect();
      } else if (this.focusIndex === 1) {
        window.dispatchEvent(new CustomEvent("holo-golf-show-leaderboard"));
      } else {
        this.showSettings();
      }
    } else if (this.currentScreen === "course_select") {
      if (this.focusIndex < 3) {
        this.hideUI();
        this.game.startCourse(this.focusIndex);
      } else {
        this.showTitle();
      }
    } else if (this.currentScreen === "settings") {
      this.showTitle();
    } else if (this.currentScreen === "paused") {
      if (this.focusIndex === 0) {
        this.hideUI();
        this.game.resume();
      } else {
        this.game.resume();
        this.showTitle();
      }
    } else if (this.currentScreen === "complete") {
      if (this.focusIndex === 0) {
        this.hideUI();
        this.game.startCourse(this.game.currentCourseIndex);
      } else {
        this.showTitle();
      }
    }
    this.audio.playMenuSelect();
  }

  handleBack() {
    if (this.currentScreen === "course_select" || this.currentScreen === "settings") {
      this.audio.playMenuSelect();
      this.showTitle();
    } else if (this.currentScreen === "paused") {
      this.audio.playMenuSelect();
      this.hideUI();
      this.game.resume();
    } else if (this.currentScreen === "complete") {
      this.audio.playMenuSelect();
      this.showTitle();
    }
  }

  handleNavNext() {
    if (this.focusableCount === 0) return;
    this.focusIndex = (this.focusIndex + 1) % this.focusableCount;
    this.audio.playMenuHover();
    this.updateFocusHighlight();
  }

  handleNavPrev() {
    if (this.focusableCount === 0) return;
    this.focusIndex = (this.focusIndex - 1 + this.focusableCount) % this.focusableCount;
    this.audio.playMenuHover();
    this.updateFocusHighlight();
  }

  private updateFocusHighlight() {
    // Remove existing focus highlights
    this.overlay.querySelectorAll("[data-focus]").forEach((el) => {
      (el as HTMLElement).style.outline = "none";
      (el as HTMLElement).style.boxShadow = "none";
    });

    // Add focus to current
    const focusId = this.focusableIds[this.focusIndex];
    if (focusId) {
      const el = this.overlay.querySelector(`#${focusId}`) as HTMLElement;
      if (el) {
        el.style.outline = "2px solid #00ffff";
        el.style.boxShadow = "0 0 15px rgba(0, 255, 255, 0.4)";
      }
    }
  }

  hideUI() {
    this.currentScreen = "";
    this.overlay.innerHTML = "";
  }

  isVisible(): boolean {
    return this.currentScreen !== "";
  }

  update(dt: number) {
    // Nothing continuous needed for HTML overlay
  }

  private buildMiniResultTable(score: any): string {
    let html = '<table style="border-collapse: collapse; font-size: 11px; width: 100%;">';
    html += '<tr style="color: #445566;">';
    for (let i = 0; i < score.holes.length; i++) {
      html += `<td style="padding: 2px 6px; text-align: center;">${i + 1}</td>`;
    }
    html += '</tr><tr>';
    for (let i = 0; i < score.holes.length; i++) {
      const h = score.holes[i];
      const diff = h.strokes - h.par;
      const color = h.strokes === 1 ? '#ffff00' : diff < 0 ? '#00ff88' : diff === 0 ? '#ffffff' : '#ff6644';
      html += `<td style="padding: 2px 6px; text-align: center; color: ${color}; font-weight: bold;">${h.strokes || '-'}</td>`;
    }
    html += '</tr></table>';
    return html;
  }

  private getBestScoreText(courseIndex: number): string {
    const best = this.game.bestScores.get(`course_${courseIndex}`);
    return best ? `Best: ${best}` : "No record yet";
  }

  private buttonStyle(color = "#00ffff", hoverColor = "#0088aa"): string {
    return `
      background: transparent;
      border: 2px solid ${color};
      color: ${color};
      font-family: 'Courier New', monospace;
      font-size: 18px;
      padding: 12px 32px;
      cursor: pointer;
      letter-spacing: 3px;
      transition: all 0.2s ease;
      text-shadow: 0 0 10px ${color};
    `;
  }

  private courseCardStyle(playable: boolean, focused = false): string {
    return `
      width: 220px; padding: 25px; text-align: center;
      border: 2px solid ${playable ? (focused ? "#ffffff" : "#00ffff") : "#223344"};
      background: rgba(0, 15, 30, 0.8);
      cursor: ${playable ? "pointer" : "default"};
      transition: all 0.2s ease;
      ${playable ? "pointer-events: auto;" : "pointer-events: none; opacity: 0.5;"}
    `;
  }

  private sliderStyle(): string {
    return `
      width: 100%; margin-top: 5px; cursor: pointer;
      accent-color: #00ffff;
    `;
  }
}

/**
 * Holo Golf VR — XR Input Handler (Round 3 Overhaul)
 * Full end-to-end XR controller support across ALL game states:
 * - Title screen: trigger/A to navigate, thumbstick to browse
 * - Course select: trigger/A to select course, thumbstick L/R to browse, B for back
 * - Playing/Aiming: trigger to putt, grip for power boost, B to reset, thumbstick to orbit
 * - Hole Complete: auto-advance or A to skip
 * - Course Complete: trigger/A to replay/menu, thumbstick to select option
 * - Scorecard: B to toggle, thumbstick to scroll
 */
import { World, Vector3, Quaternion, Group, Mesh, CylinderGeometry, MeshBasicMaterial, Color, AdditiveBlending, Line, BufferGeometry, Float32BufferAttribute, LineBasicMaterial, SphereGeometry } from "@iwsdk/core";
import { InputComponent } from "@iwsdk/core";
import { PutterController } from "./putter";
import { GameManager, GameState } from "./game";
import { UIManager } from "./ui";

const THUMBSTICK_DEADZONE = 0.3;
const THUMBSTICK_COOLDOWN = 0.25; // seconds between menu nav ticks

export class XRInputHandler {
  private world: World;
  private putter: PutterController;
  private game: GameManager;
  private ui: UIManager;

  // Controller tracking
  private prevRightPos = new Vector3();
  private prevLeftPos = new Vector3();
  private rightVelocity = new Vector3();

  // Thumbstick menu navigation
  private thumbCooldownRight = 0;
  private thumbCooldownLeft = 0;

  // Menu cursor state
  private menuCursorIndex = 0; // which menu item is "focused"
  private lastMenuScreen = "";

  // Laser pointer visualization
  private laserLine: Line;
  private laserDot: Mesh;
  private laserGroup: Group;

  // Grip boost state
  private gripHeld = false;
  private gripBoostMultiplier = 1.0;

  // Camera orbit via left thumbstick
  cameraOrbitDelta = { horizontal: 0, vertical: 0 };

  constructor(
    world: World,
    putter: PutterController,
    game: GameManager,
    ui: UIManager,
  ) {
    this.world = world;
    this.putter = putter;
    this.game = game;
    this.ui = ui;

    // Build laser pointer
    this.laserGroup = new Group();
    const lineGeo = new BufferGeometry();
    const positions = new Float32Array(6);
    lineGeo.setAttribute("position", new Float32BufferAttribute(positions, 3));
    this.laserLine = new Line(
      lineGeo,
      new LineBasicMaterial({
        color: 0x00ffff,
        transparent: true,
        opacity: 0.6,
      }),
    );
    this.laserLine.visible = false;
    this.laserGroup.add(this.laserLine);

    // Laser endpoint dot
    const dotGeo = new SphereGeometry(0.008, 8, 8);
    const dotMat = new MeshBasicMaterial({
      color: 0x00ffff,
      transparent: true,
      opacity: 0.8,
      blending: AdditiveBlending,
    });
    this.laserDot = new Mesh(dotGeo, dotMat);
    this.laserDot.visible = false;
    this.laserGroup.add(this.laserDot);

    world.scene.add(this.laserGroup);

    // Reset cursor when game state changes
    game.onStateChange(() => {
      this.menuCursorIndex = 0;
    });
  }

  update(dt: number) {
    // Tick cooldowns
    if (this.thumbCooldownRight > 0) this.thumbCooldownRight -= dt;
    if (this.thumbCooldownLeft > 0) this.thumbCooldownLeft -= dt;

    // Reset camera orbit delta
    this.cameraOrbitDelta.horizontal = 0;
    this.cameraOrbitDelta.vertical = 0;

    // Access XR input — handle both 0.3.x and 0.4.x API shapes
    const input = this.world.input as any;
    const xr = input?.xr ?? input;
    if (!xr) return;

    const rightGamepad = xr.gamepads?.right;
    const leftGamepad = xr.gamepads?.left;

    if (!rightGamepad) return;

    // Get right controller position for putter tracking
    const playerSpaceEntities = (this.world as any).playerSpaceEntities;
    const rightGripSpace = playerSpaceEntities?.gripSpaces?.right;
    const rightRaySpace = playerSpaceEntities?.raySpaces?.right;

    if (rightGripSpace) {
      const pos = new Vector3();
      const quat = new Quaternion();
      rightGripSpace.object3D.getWorldPosition(pos);
      rightGripSpace.object3D.getWorldQuaternion(quat);

      // Track velocity for swing detection
      this.rightVelocity.copy(pos).sub(this.prevRightPos);
      this.prevRightPos.copy(pos);

      this.putter.updateXR(pos, quat);
    }

    // Update laser pointer (visible in menus and aiming)
    this.updateLaserPointer(rightRaySpace || rightGripSpace);

    // Route input by game state
    const state = this.game.state;

    if (this.ui.isVisible()) {
      this.handleMenuInput(rightGamepad, leftGamepad, dt);
    } else if (state === GameState.AIMING) {
      this.handleAimingInput(rightGamepad, leftGamepad, dt);
    } else if (state === GameState.BALL_MOVING) {
      this.handleBallMovingInput(leftGamepad, dt);
    } else if (state === GameState.HOLE_COMPLETE) {
      this.handleHoleCompleteInput(rightGamepad);
    } else if (state === GameState.COURSE_COMPLETE) {
      this.handleCourseCompleteInput(rightGamepad);
    }

    // Grip button tracking (works in any state)
    const gripHeld = rightGamepad.getButtonPressed?.(InputComponent.Squeeze);
    this.gripHeld = !!gripHeld;
    if (this.gripHeld) {
      this.gripBoostMultiplier = Math.min(this.gripBoostMultiplier + dt * 0.8, 1.5);
    } else {
      this.gripBoostMultiplier = Math.max(this.gripBoostMultiplier - dt * 2.0, 1.0);
    }
  }

  // Get the grip boost multiplier for power shots
  getGripBoost(): number {
    return this.gripBoostMultiplier;
  }

  private updateLaserPointer(gripSpace: any) {
    const showLaser = this.ui.isVisible() || this.game.state === GameState.AIMING;

    if (!gripSpace || !showLaser) {
      this.laserLine.visible = false;
      this.laserDot.visible = false;
      return;
    }

    const pos = new Vector3();
    const dir = new Vector3(0, 0, -1);
    gripSpace.object3D.getWorldPosition(pos);
    gripSpace.object3D.getWorldQuaternion(new Quaternion());

    // In aiming mode, point toward the ball
    if (this.game.state === GameState.AIMING && this.putter.isAiming) {
      // Laser shows aim direction
      const ballPos = (this.game as any).ball?.position;
      if (ballPos) {
        dir.copy(this.putter.aimDirection);
      }
    }

    const end = pos.clone().add(dir.multiplyScalar(3));
    const posAttr = this.laserLine.geometry.getAttribute("position");
    const arr = posAttr.array as Float32Array;
    arr[0] = pos.x; arr[1] = pos.y; arr[2] = pos.z;
    arr[3] = end.x; arr[4] = end.y; arr[5] = end.z;
    posAttr.needsUpdate = true;

    this.laserLine.visible = true;
    this.laserDot.position.copy(end);
    this.laserDot.visible = true;
  }

  // === Menu navigation with controllers ===

  private handleMenuInput(rightGamepad: any, leftGamepad: any, dt: number) {
    // Trigger or A to select current menu item
    const triggerDown = rightGamepad.getButtonDown?.(InputComponent.Trigger);
    const aDown = rightGamepad.getButtonDown?.(InputComponent.A_Button);

    if (triggerDown || aDown) {
      this.ui.handleSelect();
    }

    // B button to go back
    const bDown = rightGamepad.getButtonDown?.(InputComponent.B_Button);
    if (bDown) {
      this.ui.handleBack();
    }

    // Thumbstick for menu navigation
    const rightThumb = rightGamepad.getAxesValues?.(InputComponent.Thumbstick);
    if (rightThumb && this.thumbCooldownRight <= 0) {
      if (rightThumb.x > THUMBSTICK_DEADZONE || rightThumb.y > THUMBSTICK_DEADZONE) {
        this.ui.handleNavNext();
        this.thumbCooldownRight = THUMBSTICK_COOLDOWN;
      } else if (rightThumb.x < -THUMBSTICK_DEADZONE || rightThumb.y < -THUMBSTICK_DEADZONE) {
        this.ui.handleNavPrev();
        this.thumbCooldownRight = THUMBSTICK_COOLDOWN;
      }
    }

    // Left thumbstick also works for navigation
    if (leftGamepad) {
      const leftThumb = leftGamepad.getAxesValues?.(InputComponent.Thumbstick);
      if (leftThumb && this.thumbCooldownLeft <= 0) {
        if (leftThumb.x > THUMBSTICK_DEADZONE) {
          this.ui.handleNavNext();
          this.thumbCooldownLeft = THUMBSTICK_COOLDOWN;
        } else if (leftThumb.x < -THUMBSTICK_DEADZONE) {
          this.ui.handleNavPrev();
          this.thumbCooldownLeft = THUMBSTICK_COOLDOWN;
        }
      }
    }
  }

  // === Aiming state (controller-based putting) ===

  private handleAimingInput(rightGamepad: any, leftGamepad: any, dt: number) {
    // Trigger fires the putt (swing detection also works via putter.updateXR)
    const triggerDown = rightGamepad.getButtonDown?.(InputComponent.Trigger);
    if (triggerDown && this.putter.isAiming) {
      // Quick-fire with current aim direction if set
      this.putter.releaseAim();
      this.game.onStroke();
    }

    // B button: pause (single press), or reset ball (hold was previous behavior)
    const bDown = rightGamepad.getButtonDown?.(InputComponent.B_Button);
    if (bDown) {
      this.game.pause();
    }

    // A button resets ball to tee
    const aDown = rightGamepad.getButtonDown?.(InputComponent.A_Button);
    if (aDown) {
      this.game.resetBall();
    }

    // Left thumbstick orbits camera around ball
    if (leftGamepad) {
      const leftThumb = leftGamepad.getAxesValues?.(InputComponent.Thumbstick);
      if (leftThumb) {
        if (Math.abs(leftThumb.x) > THUMBSTICK_DEADZONE) {
          this.cameraOrbitDelta.horizontal = leftThumb.x * dt * 2.0;
        }
        if (Math.abs(leftThumb.y) > THUMBSTICK_DEADZONE) {
          this.cameraOrbitDelta.vertical = -leftThumb.y * dt * 1.5;
        }
      }
    }
  }

  // === Ball moving (just camera orbit) ===

  private handleBallMovingInput(leftGamepad: any, dt: number) {
    if (leftGamepad) {
      const leftThumb = leftGamepad.getAxesValues?.(InputComponent.Thumbstick);
      if (leftThumb) {
        if (Math.abs(leftThumb.x) > THUMBSTICK_DEADZONE) {
          this.cameraOrbitDelta.horizontal = leftThumb.x * dt * 2.0;
        }
        if (Math.abs(leftThumb.y) > THUMBSTICK_DEADZONE) {
          this.cameraOrbitDelta.vertical = -leftThumb.y * dt * 1.5;
        }
      }
    }
  }

  // === Hole complete ===

  private handleHoleCompleteInput(rightGamepad: any) {
    const aDown = rightGamepad.getButtonDown?.(InputComponent.A_Button);
    const triggerDown = rightGamepad.getButtonDown?.(InputComponent.Trigger);

    if (aDown || triggerDown) {
      // Skip the auto-timer and go to next hole immediately
      this.game.skipToNextHole();
    }
  }

  // === Course complete ===

  private handleCourseCompleteInput(rightGamepad: any) {
    const aDown = rightGamepad.getButtonDown?.(InputComponent.A_Button);
    const triggerDown = rightGamepad.getButtonDown?.(InputComponent.Trigger);

    if (aDown || triggerDown) {
      this.ui.showCourseComplete();
    }
  }
}

/**
 * Holo Golf VR — Main Entry Point (Round 3 Overhaul)
 * Wires all systems together with course-specific theming, XR→browser camera sync,
 * and integrated environment theme switching.
 */
import {
  World,
  Color,
  AmbientLight,
  DirectionalLight,
  PointLight,
  Fog,
  Vector3,
  Group,
  Mesh,
  SphereGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  CylinderGeometry,
  BoxGeometry,
  PlaneGeometry,
  EdgesGeometry,
  LineSegments,
  LineBasicMaterial,
  RingGeometry,
  DoubleSide,
  AdditiveBlending,
} from "@iwsdk/core";
import { GameManager, GameState } from "./game";
import { BallController } from "./ball";
import { PutterController } from "./putter";
import { CourseManager } from "./course";
import { HUDManager } from "./hud";
import { UIManager } from "./ui";
import { EffectsManager } from "./effects";
import { AudioManager } from "./audio";
import { EnvironmentBuilder } from "./environment";
import { XRInputHandler } from "./xrinput";
import { BrowserInputHandler } from "./browserinput";
import { createLoadingScreen } from "./loading";
import { ControlsHelp } from "./controls";
import { AchievementTracker } from "./achievements";
import { HoleBanner } from "./banner";
import { StatsTracker } from "./stats";
import { MiniMap } from "./minimap";
import { PracticeMode } from "./practice";
import { ToastManager } from "./toast";

const container = document.getElementById("scene-container") as HTMLDivElement;

const loadingScreen = createLoadingScreen();
loadingScreen.show();
loadingScreen.setProgress(5, "Detecting hardware...");

async function detectXR(): Promise<boolean> {
  if (typeof navigator !== "undefined" && (navigator as any).xr) {
    try {
      return await (navigator as any).xr.isSessionSupported("immersive-vr");
    } catch {
      return false;
    }
  }
  return false;
}

async function main() {
  const xrAvailable = await detectXR();
  loadingScreen.setProgress(15, "Creating world...");

  const worldOpts: any = xrAvailable ? {
    xr: { offer: "once" },
    input: { canvasPointerEvents: true },
    features: {
      grabbing: false,
      locomotion: false,
      physics: false,
    },
  } : {
    xr: false,
    render: {
      near: 0.01,
      far: 500,
      camera: { position: [0, 3, 8], lookAt: [0, 0, 0] },
    },
    input: { canvasPointerEvents: true },
    features: {
      grabbing: false,
      locomotion: false,
      physics: false,
    },
  };

  const world = await World.create(container, worldOpts);

  loadingScreen.setProgress(30, "Building environment...");

  // Environment
  const env = new EnvironmentBuilder(world);
  env.build();

  loadingScreen.setProgress(45, "Initializing audio...");

  // Audio
  const audio = new AudioManager();
  await audio.init();

  loadingScreen.setProgress(55, "Loading course...");

  // Course
  const courseManager = new CourseManager(world);

  // Ball
  const ball = new BallController(world, audio);

  // Putter
  const putter = new PutterController(world, ball, audio);

  // Effects
  const effects = new EffectsManager(world);

  // Game manager
  const game = new GameManager(world, courseManager, ball, putter, effects, audio);

  // HUD
  const hud = new HUDManager(world, game);
  hud.setBall(ball);

  // UI
  const ui = new UIManager(world, game, audio);

  loadingScreen.setProgress(70, "Setting up controls...");

  // Input handlers
  const xrInput = new XRInputHandler(world, putter, game, ui);
  const browserInput = new BrowserInputHandler(world, putter, game, ball, ui, container);

  // Wire XR camera orbit into browser input system
  browserInput.xrInput = xrInput;

  // Wire ball out-of-bounds callback
  ball.onOutOfBounds = () => {
    toast.showOutOfBounds();
    hud.flashPenalty();
    game.handleBallOOB();
  };

  // Wire water hazard callback
  game.onWaterHazard = () => {
    toast.showWaterHazard();
    hud.flashPenalty();
  };

  // Achievements
  const achievements = new AchievementTracker();
  const banner = new HoleBanner();
  const stats = new StatsTracker();
  const minimap = new MiniMap(game, ball);
  const practice = new PracticeMode(game, audio);
  const toast = new ToastManager();

  // Wire practice mode into UI
  ui.practiceMode = practice;

  // Hook state changes for environment theming + achievements
  game.onStateChange((state) => {
    if (state === GameState.AIMING) {
      const hole = game.getCurrentHole();
      if (hole && game.currentStrokes === 0) {
        banner.show(hole.index + 1, hole.name, hole.par);
      }
    }
    if (state === GameState.PLAYING) {
      // Switch environment theme when starting a course
      env.applyTheme(game.currentCourseIndex);
      effects.setCourseIndex(game.currentCourseIndex);
      ball.setCourseTheme(game.currentCourseIndex);
    }
    if (state === GameState.HOLE_COMPLETE) {
      const hole = game.getCurrentHole();
      if (hole) {
        achievements.checkHole(game.currentStrokes, hole.par);
        stats.recordHole(game.currentStrokes, hole.par);

        // Show score name toast
        const scoreName = game.getScoreName(game.currentStrokes, hole.par);
        if (game.currentStrokes === 1) {
          toast.show("HOLE IN ONE!", "#ffff00", "⭐", 3.0);
        } else if (game.currentStrokes <= hole.par) {
          toast.show(scoreName, "#00ff88", "✓");
        }
      }
    }
    if (state === GameState.COURSE_COMPLETE) {
      const score = game.courseScore;
      const totalPar = score.holes.reduce((s, h) => s + h.par, 0);
      const holeInOnes = score.holes.filter((h) => h.holeInOne).length;
      achievements.checkCourse(score.totalStrokes, totalPar, score.holes);
      stats.recordRound(score.totalStrokes);

      // Record to leaderboard
      const lbResult = browserInput.leaderboard.recordScore(
        game.currentCourseIndex,
        score.courseName,
        score.totalStrokes,
        totalPar,
        holeInOnes,
      );
      if (lbResult.isNewBest) {
        toast.showNewRecord();
      }
    }
  });

  loadingScreen.setProgress(85, "Ready...");

  // Main update loop
  let lastTime = performance.now();

  const registerUpdate = (fn: () => void) => {
    if ((world as any).onUpdate) {
      (world as any).onUpdate(fn);
    } else {
      const loop = () => {
        fn();
        requestAnimationFrame(loop);
      };
      requestAnimationFrame(loop);
    }
  };

  registerUpdate(() => {
    const now = performance.now();
    const dt = Math.min((now - lastTime) / 1000, 0.05);
    lastTime = now;

    // Update game systems
    game.update(dt);
    ball.update(dt);
    putter.update(dt, world);
    courseManager.updateObstacles(dt);
    effects.update(dt);
    hud.update(dt);
    ui.update(dt);
    env.update(dt);

    // Input
    if (xrAvailable) {
      xrInput.update(dt);
    }
    browserInput.update(dt);
    achievements.update(dt);
    banner.update(dt);
    minimap.update(dt);
    toast.update(dt);
  });

  loadingScreen.setProgress(100, "Welcome to Holo Golf!");
  setTimeout(() => {
    loadingScreen.hide();
    game.setState(GameState.TITLE);
    ui.showTitle();
    audio.playAmbient();
    new ControlsHelp();
  }, 600);
}

main().catch((err) => {
  console.error("Failed to start Holo Golf:", err);
  loadingScreen.setProgress(0, "Error: " + (err as Error).message);
});

/**
 * Holo Golf VR — HUD Manager (Round 3 Overhaul)
 * In-world heads-up display: hole info, scorecard, power meter.
 * New: stroke limit indicator, course-themed colors, improved mini-map layout.
 */
import {
  World,
  Group,
  Mesh,
  PlaneGeometry,
  MeshBasicMaterial,
  Color,
  DoubleSide,
  AdditiveBlending,
  BoxGeometry,
  CanvasTexture,
  Vector3,
} from "@iwsdk/core";
import { GameManager, GameState, MAX_STROKES_PER_HOLE } from "./game";
import { BallController } from "./ball";

// Course theme colors
const COURSE_COLORS = [
  { primary: "#00ffff", secondary: "#44ff88", accent: "#0088ff" },
  { primary: "#ff44aa", secondary: "#8844ff", accent: "#cc66ff" },
  { primary: "#ff6600", secondary: "#ffaa00", accent: "#ff4400" },
];

export class HUDManager {
  private world: World;
  private game: GameManager;
  private ball: BallController | null = null;
  private hudGroup: Group;

  private canvas: HTMLCanvasElement;
  private ctx2d: CanvasRenderingContext2D;
  private texture: CanvasTexture;
  private hudMesh: Mesh;
  private dirty = true;
  private lastState: GameState = GameState.LOADING;
  private lastStrokes = 0;
  private penaltyFlashTimer = 0;

  constructor(world: World, game: GameManager) {
    this.world = world;
    this.game = game;
    this.hudGroup = new Group();

    this.canvas = document.createElement("canvas");
    this.canvas.width = 512;
    this.canvas.height = 256;
    this.ctx2d = this.canvas.getContext("2d")!;

    this.texture = new CanvasTexture(this.canvas);
    this.texture.needsUpdate = true;

    const hudGeo = new PlaneGeometry(1.6, 0.8);
    const hudMat = new MeshBasicMaterial({
      map: this.texture,
      transparent: true,
      opacity: 0.9,
      side: DoubleSide,
    });
    this.hudMesh = new Mesh(hudGeo, hudMat);
    this.hudMesh.position.set(0, 2.2, -3);
    this.hudGroup.add(this.hudMesh);

    world.scene.add(this.hudGroup);

    game.onStateChange(() => {
      this.dirty = true;
    });
  }

  setBall(ball: BallController) {
    this.ball = ball;
  }

  update(dt: number) {
    if (this.penaltyFlashTimer > 0) {
      this.penaltyFlashTimer -= dt;
      this.dirty = true;
    }

    // Always redraw during ball movement for distance display
    const isMoving = this.game.state === GameState.BALL_MOVING;

    if (this.dirty || isMoving || this.game.state !== this.lastState || this.game.currentStrokes !== this.lastStrokes) {
      this.redraw();
      this.lastState = this.game.state;
      this.lastStrokes = this.game.currentStrokes;
      this.dirty = false;
    }
  }

  flashPenalty() {
    this.penaltyFlashTimer = 1.0;
    this.dirty = true;
  }

  private getTheme() {
    return COURSE_COLORS[this.game.currentCourseIndex] || COURSE_COLORS[0];
  }

  private redraw() {
    const ctx = this.ctx2d;
    const w = this.canvas.width;
    const h = this.canvas.height;
    const theme = this.getTheme();

    ctx.clearRect(0, 0, w, h);

    // Background
    ctx.fillStyle = "rgba(0, 8, 20, 0.75)";
    ctx.fillRect(0, 0, w, h);

    // Border with course theme color
    ctx.strokeStyle = theme.primary;
    ctx.lineWidth = 2;
    ctx.strokeRect(2, 2, w - 4, h - 4);

    // Corner accents
    const cornerSize = 15;
    ctx.strokeStyle = theme.primary;
    ctx.lineWidth = 3;
    ctx.beginPath(); ctx.moveTo(2, cornerSize + 2); ctx.lineTo(2, 2); ctx.lineTo(cornerSize + 2, 2); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(w - cornerSize - 2, 2); ctx.lineTo(w - 2, 2); ctx.lineTo(w - 2, cornerSize + 2); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(2, h - cornerSize - 2); ctx.lineTo(2, h - 2); ctx.lineTo(cornerSize + 2, h - 2); ctx.stroke();
    ctx.beginPath(); ctx.moveTo(w - cornerSize - 2, h - 2); ctx.lineTo(w - 2, h - 2); ctx.lineTo(w - 2, h - cornerSize - 2); ctx.stroke();

    const state = this.game.state;

    if (
      state === GameState.PLAYING ||
      state === GameState.AIMING ||
      state === GameState.BALL_MOVING ||
      state === GameState.HOLE_COMPLETE
    ) {
      const hole = this.game.getCurrentHole();
      if (!hole) return;

      // Hole name
      ctx.fillStyle = theme.primary;
      ctx.font = "bold 28px monospace";
      ctx.textAlign = "center";
      ctx.fillText(`HOLE ${hole.index + 1}`, w / 2, 40);

      // Hole name subtitle
      ctx.fillStyle = "#6688aa";
      ctx.font = "18px monospace";
      ctx.fillText(hole.name, w / 2, 65);

      // Par info
      ctx.fillStyle = "#ffff00";
      ctx.font = "bold 22px monospace";
      ctx.textAlign = "left";
      ctx.fillText(`PAR ${hole.par}`, 25, 110);

      // Strokes with limit indicator
      const strokeColor = this.game.currentStrokes >= MAX_STROKES_PER_HOLE - 2 ? "#ff4444"
        : this.game.currentStrokes >= MAX_STROKES_PER_HOLE - 4 ? "#ffaa00"
        : "#ffffff";
      ctx.fillStyle = strokeColor;
      ctx.fillText(`STROKES: ${this.game.currentStrokes}/${MAX_STROKES_PER_HOLE}`, 25, 140);

      // Penalty flash indicator
      if (this.penaltyFlashTimer > 0) {
        const flashAlpha = Math.min(1, this.penaltyFlashTimer * 2);
        ctx.fillStyle = `rgba(255, 68, 0, ${flashAlpha * 0.3})`;
        ctx.fillRect(0, 0, w, h);
        ctx.fillStyle = `rgba(255, 68, 0, ${flashAlpha})`;
        ctx.font = "bold 18px monospace";
        ctx.textAlign = "center";
        ctx.fillText("PENALTY +1", w / 2, h / 2 + 20);
      }

      // Score relative to par
      if (this.game.currentStrokes > 0) {
        const diff = this.game.currentStrokes - hole.par;
        const scoreName = this.game.getScoreName(this.game.currentStrokes, hole.par);
        ctx.fillStyle = diff <= 0 ? "#00ff88" : "#ff4488";
        ctx.font = "bold 20px monospace";
        ctx.textAlign = "right";
        ctx.fillText(scoreName, w - 25, 110);
      }

      // Total course score
      const totalStrokes = this.game.courseScore.totalStrokes + this.game.currentStrokes;
      ctx.fillStyle = "#8888cc";
      ctx.font = "16px monospace";
      ctx.textAlign = "right";
      ctx.fillText(`TOTAL: ${totalStrokes}`, w - 25, 140);

      // Distance to hole
      if (this.ball && this.ball.isActive) {
        const dist = this.ball.position.distanceTo(hole.holePosition);
        const distM = dist.toFixed(1);
        ctx.fillStyle = "#6688aa";
        ctx.font = "14px monospace";
        ctx.textAlign = "right";
        ctx.fillText(`📏 ${distM}m to hole`, w - 25, 165);
      }

      // Mini scorecard (bottom)
      this.drawMiniScorecard(ctx, w, h, theme);

      // Hole complete overlay
      if (state === GameState.HOLE_COMPLETE) {
        const scoreName = this.game.getScoreName(this.game.currentStrokes, hole.par);
        ctx.fillStyle = "rgba(0, 20, 40, 0.6)";
        ctx.fillRect(50, 85, w - 100, 60);
        ctx.fillStyle = this.game.currentStrokes <= hole.par ? "#00ff88" : "#ffaa00";
        ctx.font = "bold 32px monospace";
        ctx.textAlign = "center";
        ctx.fillText(scoreName, w / 2, 125);
      }
    } else if (state === GameState.COURSE_COMPLETE) {
      ctx.fillStyle = "#ffff00";
      ctx.font = "bold 36px monospace";
      ctx.textAlign = "center";
      ctx.fillText("COURSE COMPLETE!", w / 2, 50);

      const score = this.game.courseScore;
      ctx.fillStyle = "#ffffff";
      ctx.font = "24px monospace";
      ctx.fillText(`Total: ${score.totalStrokes} strokes`, w / 2, 95);

      const totalPar = score.holes.reduce((s, h) => s + h.par, 0);
      const diff = score.totalStrokes - totalPar;
      ctx.fillStyle = diff <= 0 ? "#00ff88" : "#ff8844";
      ctx.fillText(
        diff === 0 ? "Even Par!" : diff < 0 ? `${diff} Under Par!` : `+${diff} Over Par`,
        w / 2,
        130,
      );

      const holeInOnes = score.holes.filter((h) => h.holeInOne).length;
      if (holeInOnes > 0) {
        ctx.fillStyle = "#ffff00";
        ctx.font = "20px monospace";
        ctx.fillText(`⭐ ${holeInOnes} Hole-in-One${holeInOnes > 1 ? "s" : ""}!`, w / 2, 165);
      }

      ctx.fillStyle = "#6688aa";
      ctx.font = "16px monospace";
      ctx.fillText("Click or press A to return to menu", w / 2, h - 25);
    }

    this.texture.needsUpdate = true;
  }

  private drawMiniScorecard(ctx: CanvasRenderingContext2D, w: number, h: number, theme: any) {
    const score = this.game.courseScore;
    const startX = 20;
    const startY = h - 70;
    const cellW = (w - 40) / 9;

    // Hole numbers
    ctx.fillStyle = "#445566";
    ctx.font = "11px monospace";
    ctx.textAlign = "center";
    for (let i = 0; i < 9; i++) {
      const x = startX + i * cellW + cellW / 2;
      ctx.fillText(`${i + 1}`, x, startY);
    }

    // Pars
    ctx.fillStyle = "#667788";
    for (let i = 0; i < 9; i++) {
      const x = startX + i * cellW + cellW / 2;
      ctx.fillText(`P${score.holes[i].par}`, x, startY + 15);
    }

    // Scores
    for (let i = 0; i < 9; i++) {
      const holeScore = score.holes[i];
      if (holeScore.strokes === 0 && i > this.game.currentHoleIndex) continue;

      const strokes = i === this.game.currentHoleIndex && holeScore.strokes === 0
        ? this.game.currentStrokes
        : holeScore.strokes;

      if (strokes === 0) continue;

      const diff = strokes - holeScore.par;
      ctx.fillStyle =
        strokes === 1 ? "#ffff00" : diff < 0 ? "#00ff88" : diff === 0 ? "#ffffff" : "#ff6644";
      ctx.font = "bold 14px monospace";
      const x = startX + i * cellW + cellW / 2;
      ctx.fillText(`${strokes}`, x, startY + 35);
    }

    // Current hole indicator
    const currentX = startX + this.game.currentHoleIndex * cellW;
    ctx.strokeStyle = theme.primary;
    ctx.lineWidth = 1;
    ctx.strokeRect(currentX, startY - 8, cellW, 50);
  }
}

/**
 * Holo Golf VR — Putter Controller
 * XR: Putter follows right controller, swing detects putt.
 * Browser: Click-and-drag power/direction mechanic.
 */
import {
  World,
  Vector3,
  Mesh,
  CylinderGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  Group,
  Color,
  BoxGeometry,
  SphereGeometry,
  LineSegments,
  EdgesGeometry,
  LineBasicMaterial,
  AdditiveBlending,
  BufferGeometry,
  Float32BufferAttribute,
  Line,
} from "@iwsdk/core";
import { BallController } from "./ball";
import { AudioManager } from "./audio";

const SHAFT_LENGTH = 0.9;
const HEAD_SIZE = 0.06;
const SWING_THRESHOLD = 0.8;
const MAX_POWER = 10.0;
const BROWSER_POWER_SCALE = 0.06;

export class PutterController {
  private world: World;
  private ball: BallController;
  private audio: AudioManager;
  private group: Group;
  private headMesh: Mesh;
  private shaftMesh: Mesh;
  private active = false;

  // XR swing tracking
  private prevControllerPos = new Vector3();
  private controllerVelocity = new Vector3();
  private isSwinging = false;
  private swingCooldown = 0;

  // Browser aiming
  aimDirection = new Vector3(0, 0, -1);
  aimPower = 0;
  isAiming = false;
  private aimLine: Line;
  private aimDots: Mesh[] = [];
  private aimGroup: Group;
  private dragStart = new Vector3();

  constructor(world: World, ball: BallController, audio: AudioManager) {
    this.world = world;
    this.ball = ball;
    this.audio = audio;

    this.group = new Group();

    // Shaft — thin glowing cylinder
    const shaftGeo = new CylinderGeometry(0.006, 0.008, SHAFT_LENGTH, 8);
    const shaftMat = new MeshStandardMaterial({
      color: new Color(0x8844ff),
      emissive: new Color(0x6622cc),
      emissiveIntensity: 0.8,
      metalness: 0.7,
      roughness: 0.2,
    });
    this.shaftMesh = new Mesh(shaftGeo, shaftMat);
    this.shaftMesh.position.y = SHAFT_LENGTH / 2;
    this.group.add(this.shaftMesh);

    // Head — flat rectangular head
    const headGeo = new BoxGeometry(HEAD_SIZE, 0.03, HEAD_SIZE * 1.8);
    const headMat = new MeshStandardMaterial({
      color: new Color(0xaa66ff),
      emissive: new Color(0x8844dd),
      emissiveIntensity: 1.0,
      metalness: 0.8,
      roughness: 0.1,
    });
    this.headMesh = new Mesh(headGeo, headMat);
    this.headMesh.position.y = 0;
    this.headMesh.position.z = HEAD_SIZE * 0.5;
    this.group.add(this.headMesh);

    // Wireframe edges on head
    const headEdges = new EdgesGeometry(headGeo);
    const edgeMat = new LineBasicMaterial({ color: 0xcc88ff, transparent: true, opacity: 0.8 });
    const wireHead = new LineSegments(headEdges, edgeMat);
    this.headMesh.add(wireHead);

    // Aim line (browser mode)
    const lineGeo = new BufferGeometry();
    const positions = new Float32Array(2 * 3);
    lineGeo.setAttribute("position", new Float32BufferAttribute(positions, 3));
    this.aimLine = new Line(
      lineGeo,
      new LineBasicMaterial({
        color: 0xff4488,
        transparent: true,
        opacity: 0.7,
      }),
    );
    this.aimLine.visible = false;

    this.aimGroup = new Group();
    world.scene.add(this.aimGroup);
    world.scene.add(this.aimLine);
    world.scene.add(this.group);
    this.group.visible = false;
  }

  setActive(active: boolean) {
    this.active = active;
    this.group.visible = active;
    if (!active) {
      this.hideAim();
    }
  }

  // === Browser aiming ===

  startAim(mouseX: number, mouseY: number) {
    if (!this.active || !this.ball.isActive) return;
    this.isAiming = true;
    this.dragStart.set(mouseX, 0, mouseY);
    this.aimPower = 0;
  }

  updateAim(mouseX: number, mouseY: number) {
    if (!this.isAiming) return;

    const dx = mouseX - this.dragStart.x;
    const dy = mouseY - this.dragStart.z;
    const dist = Math.sqrt(dx * dx + dy * dy);

    this.aimPower = Math.min(dist * BROWSER_POWER_SCALE, MAX_POWER);

    // Direction is opposite to drag (pull back = hit forward)
    if (dist > 1) {
      this.aimDirection.set(-dx / dist, 0, -dy / dist).normalize();
    }

    this.showAim();
  }

  releaseAim() {
    if (!this.isAiming) return;
    this.isAiming = false;

    if (this.aimPower > 0.1) {
      this.ball.hit(this.aimDirection.clone(), this.aimPower);
      this.audio.playSwing(this.aimPower / MAX_POWER);
    }

    this.hideAim();
    this.aimPower = 0;
  }

  private showAim() {
    if (!this.ball.isActive) return;

    const ballPos = this.ball.position.clone();
    ballPos.y = this.ball.position.y;

    // Direction line
    const lineEnd = ballPos.clone().add(this.aimDirection.clone().multiplyScalar(this.aimPower * 0.3));
    const posAttr = this.aimLine.geometry.getAttribute("position");
    (posAttr.array as Float32Array)[0] = ballPos.x;
    (posAttr.array as Float32Array)[1] = ballPos.y;
    (posAttr.array as Float32Array)[2] = ballPos.z;
    (posAttr.array as Float32Array)[3] = lineEnd.x;
    (posAttr.array as Float32Array)[4] = lineEnd.y;
    (posAttr.array as Float32Array)[5] = lineEnd.z;
    posAttr.needsUpdate = true;
    this.aimLine.visible = true;

    // Power dots
    this.aimDots.forEach((d) => this.aimGroup.remove(d));
    this.aimDots = [];

    const numDots = Math.ceil(this.aimPower * 2);
    for (let i = 0; i < numDots && i < 20; i++) {
      const t = (i + 1) / (numDots + 1);
      const dotPos = ballPos.clone().add(this.aimDirection.clone().multiplyScalar(t * this.aimPower * 0.3));
      const geo = new SphereGeometry(0.008, 6, 6);
      const mat = new MeshBasicMaterial({
        color: new Color().lerpColors(new Color(0x00ffff), new Color(0xff4488), t),
        transparent: true,
        opacity: 0.8 - t * 0.4,
        blending: AdditiveBlending,
      });
      const dot = new Mesh(geo, mat);
      dot.position.copy(dotPos);
      this.aimGroup.add(dot);
      this.aimDots.push(dot);
    }
  }

  private hideAim() {
    this.aimLine.visible = false;
    this.aimDots.forEach((d) => this.aimGroup.remove(d));
    this.aimDots = [];
  }

  // === XR Swing ===

  updateXR(controllerPos: Vector3, controllerQuat: any) {
    if (!this.active || this.swingCooldown > 0) return;

    // Track controller velocity
    this.controllerVelocity.copy(controllerPos).sub(this.prevControllerPos);
    this.prevControllerPos.copy(controllerPos);

    // Position putter at controller
    this.group.position.copy(controllerPos);
    this.group.position.y -= SHAFT_LENGTH;
    if (controllerQuat) {
      this.group.quaternion.copy(controllerQuat);
    }

    // Detect swing
    const speed = this.controllerVelocity.length() * 60; // per second
    if (speed > SWING_THRESHOLD) {
      // Check if putter head is near ball
      const headWorldPos = new Vector3();
      this.headMesh.getWorldPosition(headWorldPos);
      const dist = headWorldPos.distanceTo(this.ball.position);

      if (dist < 0.2) {
        const power = Math.min(speed * 3, MAX_POWER);
        const dir = this.controllerVelocity.clone().normalize();
        dir.y = 0;
        dir.normalize();
        this.ball.hit(dir, power);
        this.audio.playSwing(power / MAX_POWER);
        this.swingCooldown = 0.5;
      }
    }
  }

  update(dt: number, world: World) {
    if (this.swingCooldown > 0) {
      this.swingCooldown -= dt;
    }

    if (!this.active) return;

    // In browser mode, position putter near ball
    if (!this.isAiming) {
      const ballPos = this.ball.position;
      this.group.position.set(ballPos.x + 0.15, ballPos.y + SHAFT_LENGTH * 0.5, ballPos.z);
      this.group.rotation.set(0, 0, -0.15);
    }

    // Putter glow pulse
    const pulse = 0.8 + Math.sin(performance.now() * 0.003) * 0.2;
    (this.headMesh.material as MeshStandardMaterial).emissiveIntensity = pulse;
  }
}

/**
 * Holo Golf VR — Course Manager
 * Defines hole layouts and builds geometry. Each hole is a neon wireframe platform.
 * Now supports bumper collision, teleporters, wind zones, and ice surfaces.
 */
import {
  World,
  Vector3,
  Group,
  Mesh,
  BoxGeometry,
  PlaneGeometry,
  CylinderGeometry,
  MeshStandardMaterial,
  MeshBasicMaterial,
  EdgesGeometry,
  LineSegments,
  LineBasicMaterial,
  Color,
  DoubleSide,
  AdditiveBlending,
  RingGeometry,
  TorusGeometry,
  SphereGeometry,
  PointLight,
  Float32BufferAttribute,
  BufferGeometry,
  Line,
} from "@iwsdk/core";
