    for (let i = 0; i < bufferSize; i++) {
      const white = Math.random() * 2 - 1;
      last = (last + 0.02 * white) / 1.02;
      data[i] = last * 3.5;
    }

    this.rollingSource = this.ctx.createBufferSource();
    this.rollingSource.buffer = buffer;
    this.rollingSource.loop = true;

